-- ESTUDIAR · Fase E-2 (INGLÉS) — teoría de sesión + ejemplos con audio + prueba.
-- Llena el hueco que dejó E-1 en la estructura tab→nivel→tema→teoría. Contenido
-- autorado por profesores nativos + guardas deterministas + revisión adversarial.
-- SOLO inglés (course en). NO toca motor FSRS, economía, gating, certificación
-- ni los otros 5 idiomas. El quiz es FORMATIVO: califica con el grader tolerante
-- (jz_grade, mig 177) y NO paga XP/oro ni escribe user_item_attempts.

create table if not exists public.study_theory (
  id uuid primary key default gen_random_uuid(),
  course_id uuid not null references public.courses(id) on delete cascade,
  unit_order int not null,
  cefr_level text not null,
  title text not null,
  summary text not null,
  sections jsonb not null default '[]'::jsonb,
  examples jsonb not null default '[]'::jsonb,
  pitfalls jsonb not null default '[]'::jsonb,
  quiz jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (course_id, unit_order)
);

-- RLS ON sin política: el quiz lleva las respuestas → SOLO lo leen las funciones
-- SECURITY DEFINER de abajo (mismo patrón que lesson_vocab/stories.questions).
alter table public.study_theory enable row level security;
revoke all on public.study_theory from anon, authenticated;


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 1, 'A1', 'Saludos y presentarte', 'Al terminar sabrás saludar según la hora, decir tu nombre y tu país, y usar el verbo zijn con todas las personas, tuteando o tratando de usted.', '[{"heading": "Saludar y despedirte a cualquier hora", "body": "En neerlandés el saludo cambia con la hora. «Hallo» sirve casi siempre y es lo más frecuente entre gente joven. Las formas con «goede-» suenan algo más cuidadas y son las que oirás en tiendas, oficinas y con desconocidos.", "bullets": ["goedemorgen hasta el mediodía; goedemiddag por la tarde; goedenavond de noche", "«dag» sirve para saludar y para despedirte, con tono neutro", "«doei» y «tot ziens» son despedidas; «doei» es la más informal", "«hoi» es muy informal: úsalo con amigos, no en una oficina"]}, {"heading": "El verbo ZIJN (ser/estar), el más irregular", "body": "«Zijn» equivale a ser y a estar, y no sigue ninguna regla: hay que memorizarlo. Las formas son ik ben, jij/je bent, u bent, hij/zij/het is, wij zijn, jullie zijn, zij zijn. Fíjate en que el plural repite la forma del infinitivo.", "bullets": ["Singular: ik ben · jij/je bent · hij/zij/het is", "Plural: wij zijn · jullie zijn · zij zijn, siempre «zijn»", "«u bent» es la forma formal, tanto para uno como para varios", "Al invertir con jij desaparece la -t: «Ben jij Ana?»"]}, {"heading": "Presentarte: nombre, país y tuteo o usted", "body": "Para dar tu nombre tienes dos caminos igual de normales: «Ik heet Ana» o «Ik ben Ana». Preguntas con «Hoe heet je?». Para el origen se usa komen, no zijn: «Ik kom uit Spanje». Al conocer a alguien, di «Aangenaam» o «Leuk je te ontmoeten».", "bullets": ["«Hoe heet je?»: el verbo va justo después de «hoe»", "«Waar kom je vandaan?» = ¿de dónde eres?", "je/jij con conocidos; «u» con desconocidos, clientes o gente mayor", "«Aangenaam» o «Leuk je te ontmoeten» al darte la mano"]}]'::jsonb, '[{"nl": "Hallo, ik heet Sanne. Hoe heet jij?", "es": "Hola, me llamo Sanne. ¿Y tú cómo te llamas?", "text": "Hallo, ik heet Sanne. Hoe heet jij?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6394a558-5852-531d-aafd-c3f121fd9898.mp3"}, {"nl": "Goedemiddag, ik ben Tom. Aangenaam!", "es": "Buenas tardes, soy Tom. ¡Encantado!", "text": "Goedemiddag, ik ben Tom. Aangenaam!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b52acde8-6de9-5d06-b1ba-38fa48bcd9dd.mp3"}, {"nl": "Wij zijn Ana en Luis. We komen uit Peru.", "es": "Somos Ana y Luis. Venimos de Perú.", "text": "Wij zijn Ana en Luis. We komen uit Peru.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/84b2ad06-63c4-55e0-8b05-d7594fb46fdb.mp3"}, {"nl": "Waar kom je vandaan? Ik kom uit Nederland.", "es": "¿De dónde eres? Yo soy de los Países Bajos.", "text": "Waar kom je vandaan? Ik kom uit Nederland.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/07f2c845-b52f-5b37-919a-f743ef7ef49f.mp3"}]'::jsonb, '[{"title": "«Hoe je heet?» — el verbo va en 2ª posición", "body": "El español coloca el sujeto antes del verbo: «¿cómo te llamas?». En neerlandés el verbo conjugado ocupa la segunda posición de la frase principal, así que después de «hoe» viene el verbo: «Hoe heet je?», no «Hoe je heet?»."}, {"title": "«Jij ben»: a jij le falta la -t", "body": "Con ik la forma es «ben», sin -t; con jij/je y con u lleva -t: «jij bent», «u bent». El único caso en que jij pierde esa -t es cuando el verbo va delante: «Ben jij Ana?»."}, {"title": "«Ik ben uit Spanje»: el origen va con komen", "body": "Para decir de dónde eres, el neerlandés usa komen uit, no zijn: «Ik kom uit Spanje», «Zij komt uit Peru». «Ik ben Spanjaard» sí existe, pero ahí ya nombras la nacionalidad, no el país."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál de estas frases usa correctamente el verbo zijn con «jij»?", "options": ["Jij bent Nederlands.", "Jij ben Nederlands.", "Jij is Nederlands."], "answer": "Jij bent Nederlands.", "id": "u1q1"}, {"type": "multiple_choice", "prompt": "Quieres preguntarle el nombre a un compañero de clase. ¿Cuál es la frase correcta?", "options": ["Hoe heet je?", "Hoe je heet?", "Hoe jij heten?"], "answer": "Hoe heet je?", "id": "u1q2"}, {"type": "cloze", "prompt": "Completa la frase para decir de qué país eres.", "text": "Ik ___ uit Peru.", "answer": "kom", "accepted": ["kom"], "id": "u1q3"}, {"type": "cloze", "prompt": "Son las nueve de la mañana y saludas a tu vecina. Escribe el saludo propio de esa franja horaria.", "text": "___, mevrouw Jansen!", "answer": "goedemorgen", "accepted": ["goedemorgen", "goeiemorgen"], "id": "u1q4"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas preguntas está en el registro FORMAL (de usted)?", "options": ["Waar komt u vandaan?", "Waar kom je vandaan?", "Waar komen jullie vandaan?"], "answer": "Waar komt u vandaan?", "id": "u1q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 2, 'A1', 'Números, edad y de dónde vienes', 'Contarás del cero al noventa y nueve, dirás tu edad con el verbo zijn (nunca con hebben) y explicarás de qué país vienes.', '[{"heading": "Los números: del 0 al 20 y las decenas", "body": "Del 0 al 12 hay que memorizar: nul, een, twee, drie, vier, vijf, zes, zeven, acht, negen, tien, elf, twaalf. Del 13 al 19 se añade -tien: dertien, veertien, vijftien, zestien, zeventien, achttien, negentien. El número 1 suele escribirse één para no confundirlo con el artículo een.", "bullets": ["Decenas: twintig, dertig, veertig, vijftig, zestig, zeventig, tachtig, negentig, honderd.", "Ojo con los irregulares: dertien, veertien, dertig, veertig y tachtig.", "Del 21 al 99: primero la unidad, luego «en», luego la decena.", "Así: eenentwintig (21), vierendertig (34), tweeënveertig (42); todo junto."]}, {"heading": "La edad va con ZIJN; y el verbo HEBBEN", "body": "En neerlandés la edad no se tiene: se es. Se dice Ik ben twintig jaar oud, con el verbo zijn: ik ben, jij bent, hij is, wij zijn. Hebben (tener) sirve para todo lo demás: ik heb, jij hebt, hij heeft, wij hebben.", "bullets": ["Ik ben twintig jaar oud. También vale: Ik ben twintig.", "Para preguntar la edad: Hoe oud ben je?", "Tras el verbo, jij/je pierde la ‑t: ben je?, heb je?", "Ojo: hij heeft, no hij hebt; con u valen hebt y heeft."]}, {"heading": "De dónde vienes y qué nacionalidad tienes", "body": "Para el origen se usa komen uit con el país o la ciudad: Ik kom uit Peru. La pregunta lleva vandaan al final: Waar kom je vandaan? La nacionalidad y el idioma comparten palabra y van con mayúscula: Nederlands, Spaans, Peruaans. El país se escribe distinto: Nederland, Spanje, Peru.", "bullets": ["Ik kom uit Colombia. Ik kom uit Bogotá.", "Con países y ciudades se usa uit, no van.", "Vandaan cierra la pregunta: Waar kom jij vandaan?", "Ik ben Peruaans (adjetivo) o Ik ben Peruaan/Peruaanse (persona)."]}]'::jsonb, '[{"nl": "Ik ben eenentwintig jaar oud en ik kom uit Peru.", "es": "Tengo veintiún años y vengo de Perú.", "text": "Ik ben eenentwintig jaar oud en ik kom uit Peru.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/451e03a2-c821-5a43-9639-86b78c291653.mp3"}, {"nl": "Hoe oud ben je? Ik ben dertig.", "es": "¿Cuántos años tienes? Tengo treinta.", "text": "Hoe oud ben je? Ik ben dertig.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c6756467-bb25-5313-bc76-39b54ea7da72.mp3"}, {"nl": "Waar kom je vandaan? Ik kom uit Nederland.", "es": "¿De dónde vienes? Vengo de los Países Bajos.", "text": "Waar kom je vandaan? Ik kom uit Nederland.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/86b302c6-98e0-50f5-809a-37963ef0b062.mp3"}, {"nl": "Mijn broer heeft twee kinderen en hij is vijfendertig.", "es": "Mi hermano tiene dos hijos y tiene treinta y cinco años.", "text": "Mijn broer heeft twee kinderen en hij is vijfendertig.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f2e5f0a0-26da-5b7a-a972-a76589976919.mp3"}]'::jsonb, '[{"title": "«Tengo 20 años» no se dice con hebben", "body": "El calco Ik heb twintig jaar es el error número uno. En neerlandés la edad se expresa con zijn: Ik ben twintig jaar oud. Puedes acortarlo a Ik ben twintig, pero hebben no sirve para la edad."}, {"title": "Se viene «uit» un país, no «van»", "body": "El español «vengo de Perú» empuja a decir Ik kom van Peru. Con países y ciudades el neerlandés usa uit: Ik kom uit Peru. Y la pregunta lleva vandaan al final: Waar kom je vandaan?"}, {"title": "Los números del 21 al 99 van al revés", "body": "Se dice primero la unidad y después la decena, unidas por «en»: eenentwintig (21), vierendertig (34). Si lo lees de izquierda a derecha confundirás tweeëndertig (32) con drieëntwintig (23). Y no olvides esa «en» central: no eentwintig."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «Tengo veinte años» en neerlandés?", "options": ["Ik ben twintig jaar oud.", "Ik heb twintig jaar.", "Ik heb twintig jaar oud."], "answer": "Ik ben twintig jaar oud.", "id": "u2q1"}, {"type": "cloze", "prompt": "Completa con la forma correcta del verbo que en neerlandés expresa la edad.", "text": "Mijn moeder ___ vijftig jaar oud.", "answer": "is", "accepted": ["is"], "id": "u2q2"}, {"type": "multiple_choice", "prompt": "¿Cuál frase es correcta? (Él tiene dos hermanas)", "options": ["Hij heeft twee zussen.", "Hij hebt twee zussen.", "Hij heb twee zussen."], "answer": "Hij heeft twee zussen.", "id": "u2q3"}, {"type": "cloze", "prompt": "Completa la frase: estás diciendo de qué país vienes.", "text": "Ik kom ___ Peru.", "answer": "uit", "accepted": ["uit"], "id": "u2q4"}, {"type": "multiple_choice", "prompt": "¿Cómo se escribe el número 21 en neerlandés?", "options": ["eenentwintig", "twintigeen", "eentwintig"], "answer": "eenentwintig", "id": "u2q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 3, 'A1', 'La familia', 'Aprenderás a nombrar a tu familia en neerlandés con su artículo de o het, a usar mijn, zijn, haar y onze, y a formar el plural.', '[{"heading": "de of het: el artículo va con la palabra", "body": "En neerlandés hay dos artículos definidos: de y het, y no se deducen del español. Por eso la palabra se aprende siempre con su artículo. En la familia casi todo es de-woord: los pocos que llevan het conviene memorizarlos desde el primer día.", "bullets": ["de vader, de moeder, de broer, de zus, de man, de vrouw", "het kind y het gezin llevan het; en plural, de kinderen", "Los diminutivos llevan het: het broertje, het zusje, het meisje", "het gezin = padres e hijos; de familie = toda la parentela"]}, {"heading": "Posesivos: mijn, je, zijn, haar, ons", "body": "Mijn (mi), jouw o je (tu), zijn (su, de él) y haar (su, de ella) no cambian de forma. El español dice «su» para todos, así que fíjate en quién posee: zijn si es él, haar si es ella.", "bullets": ["mijn vader, mijn moeder, mijn kind, mijn ouders: mijn no cambia", "jouw zus o je zus: las dos valen, je es más frecuente", "Jan en zijn broer, pero Anna en haar broer", "ons kind (het-woord), pero onze vader y onze kinderen"]}, {"heading": "Plurales: -en, -s y el irregular kinderen", "body": "El plural se forma con ‑en o con ‑s, y lo mejor es aprenderlo con la palabra: zus → zussen, pero broer → broers. Los que acaban en ‑a o ‑o añaden apóstrofo: oma''s, opa''s. Y kind tiene un plural propio: kinderen.", "bullets": ["zus → zussen, vrouw → vrouwen, man → mannen", "broer → broers, vader → vaders, moeder → moeders", "oma → oma''s y opa → opa''s, con apóstrofo", "kind → kinderen: no existe «kinds» ni «kinden»"]}]'::jsonb, '[{"nl": "Dit is mijn vader. Hij heet Jan.", "es": "Este es mi padre. Se llama Jan.", "text": "Dit is mijn vader. Hij heet Jan.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4b8bb443-34da-5d81-9c4f-bd3d5a9568e6.mp3"}, {"nl": "Ons gezin is klein: mijn ouders, mijn zus en ik.", "es": "Nuestra familia es pequeña: mis padres, mi hermana y yo.", "text": "Ons gezin is klein: mijn ouders, mijn zus en ik.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d8a0d354-16d2-5fdb-8ff1-d437cf7b9969.mp3"}, {"nl": "Mijn broertje is vijf jaar oud.", "es": "Mi hermanito tiene cinco años.", "text": "Mijn broertje is vijf jaar oud.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/32898946-a0a3-51ed-a77f-3110ab3e39d9.mp3"}, {"nl": "Anna woont bij haar oma en opa.", "es": "Anna vive con su abuela y su abuelo.", "text": "Anna woont bij haar oma en opa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/86826c2d-45d8-538c-9cac-4850357c0ff1.mp3"}]'::jsonb, '[{"title": "El artículo no se copia del español", "body": "«El niño» es masculino en español, pero en neerlandés se dice het kind, nunca de kind. Lo mismo con het gezin y het meisje. En cambio, los diminutivos llevan het (het zusje) y todos los plurales llevan de (de zusjes)."}, {"title": "ons o onze: manda la palabra siguiente", "body": "Ons solo se usa delante de un het-woord en singular: ons kind, ons gezin. En los demás casos va onze: onze vader, onze moeder y también todos los plurales, onze ouders y onze kinderen."}, {"title": "«su» en español: zijn o haar", "body": "El español usa «su» para él y para ella, y por eso se dice mal haar vader cuando el dueño es un hombre. En neerlandés manda quien posee: Jan en zijn moeder, pero Anna en haar moeder."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la combinación correcta para «nuestro hijo» y «nuestros padres».", "options": ["ons kind, onze ouders", "onze kind, ons ouders", "onze kind, onze ouders"], "answer": "ons kind, onze ouders", "id": "u3q1"}, {"type": "multiple_choice", "prompt": "«zusje» (hermanita) es un diminutivo. Elige la forma correcta en singular y en plural.", "options": ["het zusje, de zusjes", "de zusje, de zusjes", "het zusje, het zusjes"], "answer": "het zusje, de zusjes", "id": "u3q2"}, {"type": "cloze", "prompt": "Escribe el artículo definido que falta: ¿de o het?", "text": "___ kind van Els speelt buiten.", "answer": "Het", "accepted": ["Het"], "id": "u3q3"}, {"type": "cloze", "prompt": "Escribe el plural de «kind» (es irregular).", "text": "Piet en Els hebben drie ___.", "answer": "kinderen", "accepted": ["kinderen"], "id": "u3q4"}, {"type": "cloze", "prompt": "Completa con el posesivo correcto: el dueño es Piet.", "text": "Piet gaat met ___ moeder naar Amsterdam.", "answer": "zijn", "accepted": ["zijn", "z''n"], "id": "u3q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 4, 'A1', 'Comida y bebida: pedir en el café', 'Aprenderás a pedir comida y bebida en un café neerlandés con la cortesía justa: graag, «Mag ik…?» y la cuenta, y cada palabra con su artículo.', '[{"heading": "«Graag»: la palabra que suena amable", "body": "En neerlandés la cortesía no está en el tono, está en «graag». «Ik wil een koffie» es correcto, pero suena a orden; «Ik wil graag een koffie» es lo normal en cualquier café. «Graag» va después del verbo conjugado, antes de lo que pides.", "bullets": ["Ik wil graag een koffie. = Quiero un café, por favor.", "Sin «graag» la frase es correcta, pero suena brusca.", "«Een koffie, graag» funciona igual de bien y es más corto.", "Colocación normal: sujeto + verbo + graag + lo que pides."]}, {"heading": "«Mag ik…?» y el «por favor» neerlandés", "body": "«Mag ik een koffie?» es la fórmula más frecuente al pedir. Para el «por favor» tienes dos formas: «alstublieft» si tratas de usted (u) y «alsjeblieft» si tuteas (je). Con un camarero al que no conoces, «alstublieft» es la opción segura.", "bullets": ["Mag ik een biertje, alstublieft? = ¿Me pone una cerveza?", "alstublieft = usted; alsjeblieft = tú. Misma idea, distinto trato.", "«Ik zou graag een thee willen» suena algo más formal.", "Para pedir la cuenta: De rekening, alstublieft."]}, {"heading": "La carta y la cuenta, con su artículo", "body": "En neerlandés el artículo forma parte de la palabra, así que apréndelo con ella: de koffie, de thee, de melk, de suiker, het water, het bier, het broodje. Los diminutivos en ‑je son siempre het, y en plural todo pasa a de.", "bullets": ["de koffie, de thee, de melk, de suiker, de rekening", "het water, het bier, het broodje, het gerecht", "Diminutivos en ‑je: siempre het (het biertje, het kopje).", "En plural todo lleva de: de biertjes, de broodjes."]}]'::jsonb, '[{"nl": "Een koffie en een thee, graag.", "es": "Un café y un té, por favor.", "text": "Een koffie en een thee, graag.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1989e18b-534e-5366-81b6-d50aeab7b852.mp3"}, {"nl": "Ik wil graag een broodje met kaas.", "es": "Quiero un bocadillo de queso, por favor.", "text": "Ik wil graag een broodje met kaas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/72963a92-2b72-5bb4-b631-bd3c8cbb719a.mp3"}, {"nl": "Mag ik de rekening, alstublieft?", "es": "¿Me trae la cuenta, por favor?", "text": "Mag ik de rekening, alstublieft?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0b836a2f-236a-5332-bdf3-71ba06969879.mp3"}, {"nl": "Ik zou graag een glas water willen.", "es": "Me gustaría un vaso de agua.", "text": "Ik zou graag een glas water willen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ab037404-2c37-576f-bb76-a1fb0705556e.mp3"}]'::jsonb, '[{"title": "«Ik wil een koffie» suena a orden", "body": "Traducido del español parece perfecto, pero sin «graag» un neerlandés lo oye casi como una exigencia. Añade «graag» o usa «Mag ik…?»: «Ik wil graag een koffie» / «Mag ik een koffie?»."}, {"title": "«room» no es habitación, es nata", "body": "«De room» es la nata que pones en el café; la habitación es «de kamer». Y «het gerecht» no es un juicio: es un plato de la carta. Pide «koffie met room» y te traerán café con nata."}, {"title": "alstublieft o alsjeblieft: según a quién", "body": "Las dos significan «por favor», pero «alsjeblieft» va con «je» (tú) y «alstublieft» con «u» (usted). Con un camarero que no conoces, di «alstublieft»; «alsjeblieft» déjalo para amigos. Ambas sirven también al dar algo: «aquí tienes»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "En un café, ¿cuál de estas frases es la manera cortés de pedir un café?", "options": ["Ik wil graag een koffie.", "Ik wil een koffie.", "Ik graag een koffie wil."], "answer": "Ik wil graag een koffie.", "id": "u4q1"}, {"type": "cloze", "prompt": "Completa con la palabra que convierte el pedido en algo cortés.", "text": "Ik wil ___ een broodje met kaas.", "answer": "graag", "accepted": ["graag"], "id": "u4q2"}, {"type": "cloze", "prompt": "Escribe el artículo definido que le corresponde a esta palabra.", "text": "___ water is koud.", "answer": "het", "accepted": ["het"], "id": "u4q3"}, {"type": "multiple_choice", "prompt": "Quieres un café con nata. ¿Qué pides?", "options": ["Koffie met room.", "Koffie met kamer.", "Koffie met melk."], "answer": "Koffie met room.", "id": "u4q4"}, {"type": "multiple_choice", "prompt": "Pides la cuenta a un camarero al que tratas de «u» (usted). ¿Qué dices?", "options": ["De rekening, alstublieft.", "De rekening, alsjeblieft.", "De rekening, dank u wel."], "answer": "De rekening, alstublieft.", "id": "u4q5"}]'::jsonb)
