insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 5, 'A1', 'El día y la hora', 'Aprenderás a preguntar y decir la hora en neerlandés, incluida la trampa de «half vier» (3:30), y a nombrar los días y las partes del día.', '[{"heading": "«Hoe laat is het?» — decir la hora", "body": "Para preguntar la hora dices «Hoe laat is het?» y respondes con «Het is…». Con la hora en punto añades «uur»: «Het is drie uur». Para decir a qué hora ocurre algo usas «om»: «De les begint om negen uur».", "bullets": ["«Hoe laat is het?» = ¿Qué hora es?", "«Het is vier uur.» = Son las cuatro.", "«om» marca la hora de una cita: om acht uur.", "«Hoe laat begint de les?» = ¿A qué hora empieza?"]}, {"heading": "half, kwart over y kwart voor", "body": "El neerlandés cuenta la media hora mirando hacia adelante: «half vier» es media hora camino de las cuatro, o sea 3:30. Los cuartos son sencillos: «kwart over» es «y cuarto» y «kwart voor», «menos cuarto». Los minutos sueltos funcionan igual: «tien over drie» son las 3:10.", "bullets": ["«half vier» son las 3:30, no las 4:30.", "«kwart over drie» = 3:15; «kwart voor vier» = 3:45.", "De :20 a :40 se cuenta desde la media: tien voor half vier.", "Cerca de la media: «vijf voor half vier» = 3:25."]}, {"heading": "Los días y las partes del día", "body": "Los días se escriben en minúscula: maandag, dinsdag, woensdag, donderdag, vrijdag, zaterdag, zondag. Para «el lunes» lo normal es «op maandag». Las partes del día llevan «''s» delante: ''s ochtends, ''s middags, ''s avonds y ''s nachts.", "bullets": ["Los días van en minúscula: maandag, zondag.", "«op maandag», «op zaterdag» = el lunes, el sábado.", "''s ochtends = por la mañana; ''s avonds = por la noche.", "«om acht uur ''s avonds» = a las ocho de la noche."]}]'::jsonb, '[{"nl": "Hoe laat is het? Het is half vier.", "es": "¿Qué hora es? Son las tres y media.", "text": "Hoe laat is het? Het is half vier.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/953d8be1-4dd7-5464-905c-f55e9c7aa3c6.mp3"}, {"nl": "De film begint om kwart over acht.", "es": "La película empieza a las ocho y cuarto.", "text": "De film begint om kwart over acht.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/03254c60-538a-58b9-b851-eb0e6aecd921.mp3"}, {"nl": "Op vrijdag werk ik tot kwart voor zes.", "es": "El viernes trabajo hasta las seis menos cuarto.", "text": "Op vrijdag werk ik tot kwart voor zes.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6027d0a9-0921-5c43-844a-7e4be39a99f3.mp3"}, {"nl": "''s Avonds eten we om zeven uur.", "es": "Por la noche cenamos a las siete.", "text": "''s Avonds eten we om zeven uur.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/765b316a-c2c4-5a4a-94ba-25901187ef19.mp3"}]'::jsonb, '[{"title": "«half vier» no son las cuatro y media", "body": "En español dices «cuatro y media» mirando la hora que ya pasó; el neerlandés mira la que viene. «half vier» son las 3:30 y «half zes», las 5:30. Si quedas «om half zes», llegas a las 5:30."}, {"title": "«over» y «voor» te mueven media hora", "body": "«over» es «después» y «voor» es «antes». «kwart over acht» son las 8:15; «kwart voor acht», las 7:45. Y en «vijf voor half vier» (3:25) el punto de referencia ya no es la hora, sino la media."}, {"title": "Los días van en minúscula y con «op»", "body": "A diferencia del inglés o el alemán, los días neerlandeses se escriben en minúscula: maandag, zondag. Para situarte en un día usas «op maandag»; en frases sueltas también se oye sin preposición: «Maandag ga ik naar Utrecht»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Un amigo te escribe: «We beginnen om half acht». ¿A qué hora empiezan?", "options": ["A las 7:30", "A las 8:30", "A las 8:15"], "answer": "A las 7:30", "id": "u5q1"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «a las siete de la mañana»?", "options": ["om zeven uur ''s ochtends", "om zeven uur ''s avonds", "om zeven uur ''s nachts"], "answer": "om zeven uur ''s ochtends", "id": "u5q2"}, {"type": "multiple_choice", "prompt": "¿Cuál es la frase correcta para «El domingo tomo café con mi hermana»?", "options": ["Op zondag drink ik koffie met mijn zus.", "Om zondag drink ik koffie met mijn zus.", "In zondag drink ik koffie met mijn zus."], "answer": "Op zondag drink ik koffie met mijn zus.", "id": "u5q3"}, {"type": "cloze", "prompt": "Completa la hora: son las 8:15, es decir, un cuarto DESPUÉS de las ocho.", "text": "Het is kwart ___ acht.", "answer": "over", "accepted": ["over", "na"], "id": "u5q4"}, {"type": "cloze", "prompt": "Completa con el día de la semana: «El sábado voy al mercado».", "text": "Op ___ ga ik naar de markt.", "answer": "zaterdag", "accepted": ["zaterdag"], "id": "u5q5"}]'::jsonb)
