insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 8, 'A2', 'Planes y futuro', 'Aprenderás a contar tus planes con «gaan» + infinitivo al final, a ofrecer y prometer con «zullen» y a colocar el verbo en segunda posición.', '[{"heading": "«gaan» + infinitivo: el infinitivo va al final", "body": "Para hablar de planes usas «gaan» conjugado y el otro verbo en infinitivo, pero ese infinitivo se va al FINAL de la frase. Todo lo demás (tiempo, lugar, objeto) se queda en medio: Ik ga morgen in Utrecht werken.", "bullets": ["ik ga, jij gaat, hij gaat, wij gaan, jullie gaan.", "El segundo verbo va en infinitivo, sin marca de persona.", "Ik ga morgen in Utrecht werken. (infinitivo al final)", "Entre «gaan» y ese infinitivo cabe todo lo demás."]}, {"heading": "Con el marcador delante, el verbo no se mueve", "body": "El verbo conjugado ocupa la segunda posición en la frase afirmativa (en la pregunta sin interrogativa va primero: «Zal ik je helpen?»). Si empiezas por el marcador de tiempo, el verbo se queda ahí y el sujeto salta detrás: Morgen ga ik naar Utrecht. Decir «Morgen ik ga» es el calco español más frecuente.", "bullets": ["Ik ga volgend jaar naar Spanje. (sujeto delante)", "Volgend jaar ga ik naar Spanje. (marcador delante)", "*Morgen ik ga no existe: el sujeto va detrás.", "«Volgend jaar» cuenta como un solo bloque inicial."]}, {"heading": "«zullen» y el presente con marcador", "body": "«Zullen» sirve sobre todo para ofrecerte y para prometer: Zal ik je helpen?, Ik zal het doen. Y para un plan ya fijado basta el presente con un marcador de tiempo: Morgen werk ik thuis. Las tres formas conviven en el habla diaria.", "bullets": ["Zal ik je helpen? = ¿Te ayudo? (ofrecimiento)", "Ik zal het morgen doen. (promesa)", "Morgen werk ik thuis. (presente con marcador)", "Para planes normales, «gaan» es lo más habitual."]}]'::jsonb, '[{"nl": "Ik ga morgen in Utrecht werken.", "es": "Mañana voy a trabajar en Utrecht.", "text": "Ik ga morgen in Utrecht werken.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/872b7beb-a074-5520-a616-963c12b52d3f.mp3"}, {"nl": "Volgend jaar gaan we naar Spanje verhuizen.", "es": "El año que viene nos vamos a mudar a España.", "text": "Volgend jaar gaan we naar Spanje verhuizen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1435f3fc-fcb5-5ec2-b2f5-abc626081473.mp3"}, {"nl": "Zal ik even koffie zetten?", "es": "¿Hago un café?", "text": "Zal ik even koffie zetten?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4f01e6af-fe22-53c7-8e31-5cd88d7cd472.mp3"}, {"nl": "Morgen werk ik thuis en dan bel ik je.", "es": "Mañana trabajo en casa y luego te llamo.", "text": "Morgen werk ik thuis en dan bel ik je.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/12809a98-1de9-5e14-a5d5-b0a76614020a.mp3"}]'::jsonb, '[{"title": "«Ik ga werken morgen» ✗", "body": "Es el calco de «voy a trabajar mañana». En neerlandés el infinitivo cierra la frase y el marcador de tiempo va antes: Ik ga morgen werken. Dejar el infinitivo en medio suena a extranjero."}, {"title": "«Morgen ik ga» ✗", "body": "Al empezar por el marcador de tiempo, el verbo conjugado sigue en segunda posición y el sujeto pasa detrás: Morgen ga ik naar Utrecht. El español coloca el sujeto delante; el neerlandés lo invierte en la frase principal."}, {"title": "Conjugar el verbo que sigue a «gaan»", "body": "Después de «gaan» o de «zullen», el otro verbo se queda en infinitivo: Ik ga fietsen, no *Ik ga fiets. Solo «gaan» y «zullen» llevan la marca de persona; el segundo verbo no la lleva."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Empiezas la frase con «Morgen». ¿Cuál es el orden correcto?", "options": ["Morgen werk ik in Utrecht.", "Morgen ik werk in Utrecht.", "Morgen in Utrecht ik werk."], "answer": "Morgen werk ik in Utrecht.", "id": "u8q1"}, {"type": "multiple_choice", "prompt": "«Mañana voy a trabajar». ¿Cuál es la frase neerlandesa correcta?", "options": ["Ik ga morgen werken.", "Ik ga werken morgen.", "Ik ga morgen werk."], "answer": "Ik ga morgen werken.", "id": "u8q2"}, {"type": "multiple_choice", "prompt": "Ofreces ayuda a un amigo con las maletas. ¿Qué dices?", "options": ["Zal ik je met de koffers helpen?", "Zal ik je met de koffers geholpen?", "Zal ik je met de koffers help?"], "answer": "Zal ik je met de koffers helpen?", "id": "u8q3"}, {"type": "cloze", "prompt": "Completa con el verbo «mudarse» en la forma que pide «gaan».", "text": "Volgend jaar ga ik naar Rotterdam ___.", "answer": "verhuizen", "accepted": ["verhuizen"], "id": "u8q4"}, {"type": "cloze", "prompt": "Prometes algo. Completa con la forma de «zullen» para «ik».", "text": "Ik ___ het morgen doen.", "answer": "zal", "accepted": ["zal"], "id": "u8q5"}]'::jsonb)
