insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 9, 'A2', 'De viaje: el perfectum con hebben o zijn', 'Contarás tu viaje en pasado eligiendo bien entre hebben y zijn, y manejarás el vocabulario del tren con su artículo, incluido el falso amigo «vertraging».', '[{"heading": "El perfectum con zijn: destino y cambio", "body": "La mayoría de los verbos forman el perfectum con hebben, pero un grupo pide zijn: los que expresan un desplazamiento CON destino y los que marcan un cambio de estado. El auxiliar se conjuga (ben, bent, is, zijn) y el participio va al final.", "bullets": ["Ik ben naar Amsterdam gegaan. · Hij is thuis gebleven.", "Ze is om zeven uur vertrokken. · We zijn aangekomen.", "Cambio de estado: worden, beginnen. Y blijven, que no cambia nada, también pide zijn.", "Con hebben: Ik heb op het station een kaartje gekocht."]}, {"heading": "Movimiento sin destino: hebben, no zijn", "body": "Cuidado con la regla fácil «si hay movimiento, zijn»: es falsa. Reizen, lopen, fietsen y zwemmen van con hebben cuando solo cuentas la actividad, sin decir adónde. En cuanto añades un destino (naar huis, naar het station), el mismo verbo cambia a zijn.", "bullets": ["Ik heb veel gereisd. · We hebben een uur gelopen.", "Ik ben naar huis gelopen. · Hij is naar Gent gefietst.", "La pregunta clave: ¿aparece un destino en la frase?", "Gaan, komen, vertrekken y aankomen llevan zijn siempre."]}, {"heading": "Vocabulario del viaje, con su artículo", "body": "En neerlandés el artículo forma parte de la palabra: de trein, het station, het perron, de reis, het vliegtuig, de koffer. Para el medio de transporte se dice met de trein, met de fiets, met het vliegtuig. Y «een kaartje kopen» es comprar el billete.", "bullets": ["de vertraging = el retraso; de reis = el viaje.", "met de trein, met de fiets, met het vliegtuig", "El plural lleva siempre de: de treinen, de koffers.", "Diminutivo, siempre het: het kaartje, het treintje."]}]'::jsonb, '[{"nl": "Vorige week ben ik met de trein naar Rotterdam gegaan.", "es": "La semana pasada fui a Róterdam en tren.", "text": "Vorige week ben ik met de trein naar Rotterdam gegaan.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e809f737-be3a-51a1-b668-fa31a9d7aa8e.mp3"}, {"nl": "Mijn ouders hebben vroeger veel gereisd, maar nu niet meer.", "es": "Mis padres viajaron mucho antes, pero ya no.", "text": "Mijn ouders hebben vroeger veel gereisd, maar nu niet meer.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/88990bd3-dbd3-5dfb-beb2-55320b84410c.mp3"}, {"nl": "De trein naar Utrecht heeft twintig minuten vertraging.", "es": "El tren a Utrecht lleva veinte minutos de retraso.", "text": "De trein naar Utrecht heeft twintig minuten vertraging.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b5ba3cd4-6352-52c7-820d-ac20175e82e4.mp3"}, {"nl": "Ik heb een kaartje gekocht en ben naar het perron gelopen.", "es": "Compré un billete y fui andando al andén.", "text": "Ik heb een kaartje gekocht en ben naar het perron gelopen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/109ce9e8-8264-5755-964b-9b2f84f61507.mp3"}]'::jsonb, '[{"title": "«Ik heb gegaan» no existe", "body": "Es el error número uno: traducir «he ido» por «ik heb gegaan». Gaan pide zijn, así que es «ik ben naar Amsterdam gegaan». Lo mismo con komen, vertrekken, aankomen y blijven: ben, bent, is, zijn."}, {"title": "Movimiento no es sinónimo de zijn", "body": "La regla «si hay movimiento, zijn» te hace fallar justo con el vocabulario de este tema. Reizen, lopen, fietsen y zwemmen van con hebben cuando no dices adónde: «Ik heb veel gereisd». Con destino, zijn: «Ik ben naar huis gelopen»."}, {"title": "«Vertraging» es el retraso, no un traslado", "body": "«De trein heeft vertraging» significa que el tren lleva retraso, no que haga un traslado ni que dure ese tiempo. El viaje es «de reis», el billete es «het kaartje» y el andén, «het perron»."}]'::jsonb, '[{"type": "cloze", "prompt": "Completa con el auxiliar del perfectum.", "text": "Vorige zomer ___ ik met het vliegtuig naar Spanje gegaan.", "answer": "ben", "accepted": ["ben"], "id": "u9q1"}, {"type": "cloze", "prompt": "Completa con el auxiliar del perfectum de «reizen».", "text": "Mijn ouders ___ vroeger veel gereisd.", "answer": "hebben", "accepted": ["hebben"], "id": "u9q2"}, {"type": "multiple_choice", "prompt": "Ayer volviste andando a casa. ¿Qué frase es correcta?", "options": ["Ik ben gisteren naar huis gelopen.", "Ik heb gisteren naar huis gelopen.", "Ik ben gisteren naar huis geloopt."], "answer": "Ik ben gisteren naar huis gelopen.", "id": "u9q3"}, {"type": "multiple_choice", "prompt": "«De trein naar Utrecht heeft twintig minuten vertraging» significa:", "options": ["El tren a Utrecht lleva veinte minutos de retraso.", "El tren a Utrecht sale dentro de veinte minutos.", "El tren a Utrecht tarda veinte minutos en llegar."], "answer": "El tren a Utrecht lleva veinte minutos de retraso.", "id": "u9q4"}, {"type": "cloze", "prompt": "Completa con el artículo que lleva la palabra «station».", "text": "Ik heb mijn kaartje op ___ station gekocht.", "answer": "het", "accepted": ["het", "''t"], "id": "u9q5"}]'::jsonb)
