insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 10, 'A2', 'Comer fuera y comprar', 'Aprenderás a comparar en neerlandés con ‑er y «dan», a formar el superlativo con ‑st y a moverte en la tienda y en el restaurante.', '[{"heading": "Comparar: adjetivo + ‑er y el enlace «dan»", "body": "En neerlandés el comparativo se forma añadiendo ‑er al adjetivo, sin palabra delante (los adjetivos largos y los participios sí usan meer): goedkoop → goedkoper. Si el adjetivo acaba en ‑r se añade ‑der, porque así se pronuncia mejor: duur → duurder. El segundo término se introduce con dan; als queda para la igualdad.", "bullets": ["Acaba en ‑r → ‑der: duur → duurder, lekker → lekkerder.", "groot → groter: se pierde una vocal, la sílaba queda abierta.", "Igualdad: net zo duur als, even duur als (aquí sí «als»).", "Delante del sustantivo toma -e: een grotere maat, een goedkopere jas."]}, {"heading": "El superlativo: het ‑st y de/het ‑ste", "body": "El superlativo añade ‑st al adjetivo. Delante de un sustantivo lleva artículo y termina en ‑ste: de goedkoopste jas, het kleinste kind. Sin sustantivo detrás se dice het + ‑st: dit gerecht is het lekkerst. El grupo con el que comparas se introduce con van.", "bullets": ["klein → het kleinst → de kleinste maat van de winkel.", "Predicativo: Dit gerecht is het lekkerst van de kaart.", "El grupo va con van: de beste van de klas.", "«meest» se reserva a adjetivos largos: het meest gelezen boek."]}, {"heading": "Irregulares y las palabras de tienda y mesa", "body": "Unas pocas palabras muy frecuentes hacen el comparativo y el superlativo de forma irregular, igual que bueno, mejor, el mejor en español. Se aprenden de memoria y no hay más regla. Con ellas y cuatro palabras de tienda y restaurante resuelves casi cualquier compra o comida.", "bullets": ["goed → beter → best; veel → meer → meest.", "weinig → minder → minst; graag → liever → liefst.", "Winkel: Wat kost het? · Ik zoek… · de maat · passen.", "Restaurant: bestellen · het voorgerecht · het hoofdgerecht · de rekening."]}]'::jsonb, '[{"nl": "Deze fiets is goedkoper dan die van mijn broer.", "es": "Esta bici es más barata que la de mi hermano.", "text": "Deze fiets is goedkoper dan die van mijn broer.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/10545f4b-a481-5494-a0c2-0eac30907346.mp3"}, {"nl": "Dit is het beste restaurant van de stad, maar ook het duurste.", "es": "Este es el mejor restaurante de la ciudad, pero también el más caro.", "text": "Dit is het beste restaurant van de stad, maar ook het duurste.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ac5eb797-ae3e-5020-92b1-6e59d36e75bf.mp3"}, {"nl": "Mag ik deze trui passen? Hebt u een grotere maat?", "es": "¿Me puedo probar este jersey? ¿Tiene una talla más grande?", "text": "Mag ik deze trui passen? Hebt u een grotere maat?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ae98d08a-2a00-54be-8239-75b3c4117b97.mp3"}, {"nl": "Mogen wij de rekening, alstublieft? Het eten was heerlijk.", "es": "¿Nos trae la cuenta, por favor? La comida estaba deliciosa.", "text": "Mogen wij de rekening, alstublieft? Het eten was heerlijk.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7d0b35f8-52fd-5a10-9133-87c1241fde52.mp3"}]'::jsonb, '[{"title": "«groter als» se oye mucho, pero se escribe «dan»", "body": "Muchísimos neerlandeses dicen «groter als» al hablar, y nadie te corrige en un bar. Pero la norma escrita, la escuela y los exámenes piden dan detrás de un comparativo. Usa dan, y guarda als para la igualdad: net zo groot als."}, {"title": "No digas «meer groot»: el neerlandés cambia el final", "body": "El español pone una palabra delante (más grande), el neerlandés cambia la terminación: groter. Con el superlativo, igual: het grootst, no «het meest groot». Reserva meer y meest para adjetivos largos o participios, como het meest gelezen boek."}, {"title": "«passen» y «de map»: dos falsos amigos", "body": "Passen no es pasar: significa probarse una prenda o encajar (Mag ik het passen?). Y de map no es un mapa, es una carpeta; el mapa es de kaart o de plattegrond. Para pasar di langskomen o gebeuren."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es el comparativo correcto del adjetivo «groot» (grande)?", "options": ["groter", "grooter", "meer groot"], "answer": "groter", "id": "u10q1"}, {"type": "cloze", "prompt": "Completa la comparación con la palabra que pide la norma escrita.", "text": "Deze jas is duurder ___ die trui.", "answer": "dan", "accepted": ["dan"], "id": "u10q2"}, {"type": "multiple_choice", "prompt": "¿Qué frase es correcta?", "options": ["Dit is het goedkoopste hotel van de stad.", "Dit is de goedkoopste hotel van de stad.", "Dit is het meer goedkope hotel van de stad."], "answer": "Dit is het goedkoopste hotel van de stad.", "id": "u10q3"}, {"type": "cloze", "prompt": "Escribe el comparativo irregular del adjetivo «goed» (bueno).", "text": "Dit restaurant is ___ dan dat op de hoek.", "answer": "beter", "accepted": ["beter"], "id": "u10q4"}, {"type": "cloze", "prompt": "Escribe el infinitivo del falso amigo que significa «probarse» una prenda.", "text": "Mag ik deze broek even ___?", "answer": "passen", "accepted": ["passen"], "id": "u10q5"}]'::jsonb)
