insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 11, 'A2', 'Personas y descripciones', 'Contarás cómo era todo con was, waren, had y hadden, formarás el imperfectum regular y pondrás la -e del adjetivo donde toca.', '[{"heading": "Was, waren, had, hadden: el pasado que más oirás", "body": "El imperfectum (onvoltooid verleden tijd) describe cómo eran las cosas. Las formas más frecuentes son irregulares y no llevan -t: zijn → was en singular y waren en plural; hebben → had y hadden. Con ellas hablas del tiempo, del estado de ánimo y de lo que tenías.", "bullets": ["zijn → ik/jij/hij was · wij/jullie/zij waren", "hebben → ik/jij/hij had · wij/jullie/zij hadden", "En el imperfectum «jij» no lleva -t: jij was, jij had", "«Het was mooi weer» = hacía buen tiempo; «Ik had honger» = tenía hambre"]}, {"heading": "Verbos regulares: -te o -de con ''t kofschip", "body": "Toma la raíz (el infinitivo sin -en) y alarga la vocal si hace falta: wonen → woon, maken → maak. Si esa raíz acaba en una consonante de ''t kofschip, añade -te; si acaba en cualquier otra, añade -de. El plural solo suma una -n.", "bullets": ["''t kofschip (t, k, f, s, ch, p) → -te: werkte, kookte, fietste", "El resto → -de: woonde, hoorde, leerde, betaalde", "Excepción: leven → leefde, reizen → reisde (manda la v o la z)", "Misma forma para ik, jij y hij; el plural añade -n"]}, {"heading": "Describir o contar + la -e del adjetivo", "body": "El imperfectum pinta el decorado: cómo era todo, qué había, cómo te sentías. Para contar un hecho puntual, el neerlandés hablado prefiere el perfectum. Y delante del sustantivo el adjetivo casi siempre lleva -e: de aardige man, het grote huis, een slimme vrouw.", "bullets": ["Fondo: «Het was koud en ik had geen jas.»", "Hecho: «Ik heb mijn baas gebeld.» (de baas = el jefe)", "de aardige man · het grote huis · de slimme kinderen", "Tras «een» + het-woord, sin -e: een groot huis, koud water"]}]'::jsonb, '[{"nl": "Vroeger was ik heel verlegen.", "es": "Antes yo era muy tímido.", "text": "Vroeger was ik heel verlegen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8aec1272-1776-5879-bb71-ec55c2dcdb61.mp3"}, {"nl": "Mijn opa was een grappige man met een grijze baard.", "es": "Mi abuelo era un hombre gracioso con una barba gris.", "text": "Mijn opa was een grappige man met een grijze baard.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/011f72bb-c67c-592f-a834-8ade1d35929b.mp3"}, {"nl": "We waren moe en hadden honger.", "es": "Estábamos cansados y teníamos hambre.", "text": "We waren moe en hadden honger.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6580fe39-c14b-5968-a0d3-56dd9ba2666b.mp3"}, {"nl": "Ze werkte in een klein café en woonde boven de winkel.", "es": "Ella trabajaba en un café pequeño y vivía encima de la tienda.", "text": "Ze werkte in een klein café en woonde boven de winkel.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/23c06003-1098-5224-a353-05956828f987.mp3"}]'::jsonb, '[{"title": "«Slim» es listo, no delgado", "body": "«Slim» significa listo, inteligente: «Ze is heel slim». Para delgado, el neerlandés usa slank o dun: «Hij is slank». Y «raar» no engaña: significa raro, extraño, igual que en español."}, {"title": "La -e del adjetivo delante del sustantivo", "body": "Delante del sustantivo el adjetivo casi siempre lleva -e: een aardige man, het grote huis. La excepción diaria: «een» (o sin artículo) + het-woord → sin -e: een groot huis, koud water. Detrás del verbo se queda desnudo: het huis is groot."}, {"title": "Contar en pasado: mejor el perfectum", "body": "Para un hecho puntual («ayer vendí mi bici»), el neerlandés hablado usa el perfectum: «Ik heb mijn fiets verkocht». El imperfectum (ik verkocht) suena a narración escrita. Reserva was, had, woonde y werkte para describir el fondo."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Vroeger ___ mijn ouders heel streng.» (mis padres eran muy estrictos)", "options": ["waren", "was", "zijn"], "answer": "waren", "id": "u11q1"}, {"type": "multiple_choice", "prompt": "«Un niño listo». Recuerda que kind es het-woord. Elige la forma correcta:", "options": ["een slim kind", "een slimme kind", "het slim kind"], "answer": "een slim kind", "id": "u11q2"}, {"type": "cloze", "prompt": "Completa con el imperfectum de «hebben». Fíjate en el sujeto.", "text": "Vroeger ___ we een hond, maar nu niet meer.", "answer": "hadden", "accepted": ["hadden"], "id": "u11q3"}, {"type": "cloze", "prompt": "Completa con el imperfectum de «spelen» (jugar). Aplica la regla de ''t kofschip.", "text": "Als kind ___ ik elke dag buiten.", "answer": "speelde", "accepted": ["speelde"], "id": "u11q4"}, {"type": "multiple_choice", "prompt": "«Ayer llamé a mi jefe» es un hecho puntual. En neerlandés hablado se dice:", "options": ["Gisteren heb ik mijn baas gebeld.", "Gisteren ik heb mijn baas gebeld.", "Gisteren heb ik mijn baas bellen."], "answer": "Gisteren heb ik mijn baas gebeld.", "id": "u11q5"}]'::jsonb)
