  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 12, 'A2', 'Salud, cuerpo y consejos', 'Sabrás decir qué te duele con palabras como «hoofdpijn», nombrar el cuerpo con su artículo y dar consejos con «moeten» y «zou moeten».', '[{"heading": "El dolor se pega a la parte: hoofdpijn", "body": "En neerlandés el dolor y la parte del cuerpo forman UNA sola palabra: hoofd + pijn → hoofdpijn. Y se usa con hebben, como el «tengo» español. Las más frecuentes son hoofdpijn, buikpijn, keelpijn, rugpijn y kiespijn.", "bullets": ["«Ik heb hoofdpijn», «ik heb buikpijn», «ik heb keelpijn».", "Va todo pegado: hoofdpijn, nunca partido en dos palabras.", "Siempre con hebben: «Heb je kiespijn?», «Hij heeft rugpijn».", "Para partes sin compuesto: «Mijn knie doet pijn», «Mijn schouder doet pijn»."]}, {"heading": "El cuerpo con su artículo: het hoofd, de rug", "body": "Cada parte del cuerpo lleva su artículo y se aprende junto con la palabra: het hoofd, pero de rug. No hay una regla fiable que lo prediga. Dos cosas sí son seguras: el diminutivo es het (het handje) y el plural lleva de.", "bullets": ["Con het: het hoofd, het been, het oog, het oor.", "Con de: de rug, de keel, de buik, de arm, de hand.", "En plural, siempre de: de armen, de benen, de ogen.", "Guarda el artículo con la palabra, no lo adivines luego."]}, {"heading": "Consejos con moeten y zou moeten", "body": "Para aconsejar usas «moeten»: «Je moet rusten». El verbo conjugado va en segunda posición y el infinitivo se marcha al final de la frase. Con «zou … moeten» el consejo suena más suave, como «deberías»; los dos verbos cierran la frase juntos.", "bullets": ["«Je moet rusten», «Je moet veel water drinken».", "El infinitivo se coloca al final, no junto al primer verbo.", "Más suave: «Je zou naar de huisarts moeten gaan».", "En la consulta: «de huisarts», «het recept», «de apotheek»."]}]'::jsonb, '[{"nl": "Ik heb al twee dagen keelpijn en koorts.", "es": "Llevo ya dos días con dolor de garganta y fiebre.", "text": "Ik heb al twee dagen keelpijn en koorts.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7ce907cd-0258-5f6a-95d0-d26cdbe69fcb.mp3"}, {"nl": "Mijn rug doet pijn van het tillen.", "es": "Me duele la espalda de levantar peso.", "text": "Mijn rug doet pijn van het tillen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6c3eb6b6-ec10-5964-a4dd-a10d92cfff09.mp3"}, {"nl": "Je moet vandaag thuis blijven en veel drinken.", "es": "Hoy tienes que quedarte en casa y beber mucho.", "text": "Je moet vandaag thuis blijven en veel drinken.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d4fa6534-70a0-5188-b8e2-b36b9e568588.mp3"}, {"nl": "Je zou echt naar de huisarts moeten gaan.", "es": "Deberías ir de verdad al médico de cabecera.", "text": "Je zou echt naar de huisarts moeten gaan.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8392b803-baa4-51cd-a372-ec0fa5ee0464.mp3"}]'::jsonb, '[{"title": "«hoofd pijn» no: el compuesto va pegado", "body": "El compuesto se escribe en una sola palabra: hoofdpijn, buikpijn, keelpijn. Partirlo en dos, o calcar el español con van («pijn van mijn hoofd»), suena mal. Para partes sin compuesto habitual sí se dice «Ik heb pijn in mijn knie»."}, {"title": "El infinitivo se marcha al final", "body": "El español pega el infinitivo al primer verbo: «debes beber mucha agua». El neerlandés lo manda al final: «Je moet veel water drinken». Con zou, los dos verbos cierran juntos la frase: «Je zou meer moeten rusten»."}, {"title": "het been, de rug: el artículo va con la palabra", "body": "Decir «de been» o «het rug» delata al principiante, y el artículo no se deduce del significado. Apréndelo desde el primer día junto a la palabra: het hoofd, het been, het oog, de rug, de keel, de arm."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es la forma natural de decir «me duele la cabeza»?", "options": ["Ik heb hoofdpijn.", "Ik heb hoofd pijn.", "Ik heb pijn van mijn hoofd."], "answer": "Ik heb hoofdpijn.", "id": "u12q1"}, {"type": "cloze", "prompt": "Completa con el verbo de obligación conjugado para «je». No escribas el infinitivo.", "text": "Je bent ziek: je ___ vandaag thuis blijven.", "answer": "moet", "accepted": ["moet"], "id": "u12q2"}, {"type": "multiple_choice", "prompt": "¿Qué frase da bien el consejo «deberías descansar más»?", "options": ["Je zou meer moeten rusten.", "Je zou moeten meer rusten.", "Je zou meer moet rusten."], "answer": "Je zou meer moeten rusten.", "id": "u12q3"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas partes del cuerpo lleva «het»?", "options": ["het been", "het rug", "het keel"], "answer": "het been", "id": "u12q4"}, {"type": "cloze", "prompt": "Completa con el lugar donde te entregan los medicamentos.", "text": "De huisarts schrijft een recept en je haalt de pillen bij de ___.", "answer": "apotheek", "accepted": ["apotheek"], "id": "u12q5"}]'::jsonb)
