insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 13, 'B1', 'Cortesía y deseos con «zou» + infinitivo', 'Sabrás pedir con cortesía, expresar deseos y dar consejos suaves con «zou» + infinitivo, colocando el segundo verbo al final de la frase.', '[{"heading": "El condicional en dos piezas: zou + infinitivo", "body": "El condicional español es una sola palabra («iría»); el neerlandés son dos piezas: «zou» en segunda posición y el infinitivo cerrando la frase. «Zou» vale para ik, jij, hij, zij y u en singular; con wij, jullie y zij en plural se dice «zouden».", "bullets": ["«Ik zou graag naar Japan gaan»: zou segundo, gaan al final.", "Singular: ik, jij, hij, u zou. Plural: wij, jullie, zij zouden.", "En singular «zou» no cambia de forma con ninguna persona.", "En preguntas de sí/no «zou» va primero; tras interrogativa, segundo."]}, {"heading": "Pedir con cortesía: «Zou je…?» y «Ik zou graag…»", "body": "Para pedir algo sin sonar brusco, arrancas la pregunta con «Zou je…?» o «Zou u…?» y dejas el infinitivo al final: «Zou je me even kunnen helpen?». En una tienda, en la consulta o por teléfono existe además una fórmula fija muy usada.", "bullets": ["«Zou je me even kunnen helpen?» suena mucho más suave.", "Con desconocidos usa «u»: «Zou u het raam willen openen?».", "Fórmula fija: «Ik zou graag … willen» + infinitivo.", "El «even» dentro de la frase la vuelve todavía más amable."]}, {"heading": "Consejos suaves: «zou moeten» y deseos con «als»", "body": "«Zou moeten» convierte la orden en consejo: «Je moet rusten» suena tajante; «Je zou moeten rusten» es un «deberías». Tras «zou», el segundo verbo se queda en infinitivo: moeten, nunca «moet». Y para un deseo cortés tienes «Ik zou het fijn vinden als…».", "bullets": ["«Je zou eens met je baas moeten praten»: consejo, no orden.", "«Moet» ordena; «zou moeten» sugiere y deja salida.", "«Ik zou het fijn vinden als je even belt».", "Para imaginar: «Wat zou jij in mijn plaats doen?»."]}]'::jsonb, '[{"nl": "Zou je me even kunnen helpen met dit formulier?", "es": "¿Me podrías ayudar un momento con este formulario?", "text": "Zou je me even kunnen helpen met dit formulier?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/10da81a3-3070-56b8-b4f5-0db6ff290ebc.mp3"}, {"nl": "Ik zou graag een kopje koffie willen.", "es": "Me gustaría un café.", "text": "Ik zou graag een kopje koffie willen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5634237e-672a-5bff-afe0-fe23d048c029.mp3"}, {"nl": "Je zou eens met je huisarts moeten praten.", "es": "Deberías hablar alguna vez con tu médico de cabecera.", "text": "Je zou eens met je huisarts moeten praten.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fc52eb3b-5134-584b-aae3-6bf03a011141.mp3"}, {"nl": "Ik zou het fijn vinden als je meegaat.", "es": "Me gustaría que vinieras conmigo.", "text": "Ik zou het fijn vinden als je meegaat.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0fc3356a-63bb-5360-a1d9-90da9e5c0b64.mp3"}]'::jsonb, '[{"title": "El infinitivo se queda a media frase", "body": "El español junta los dos verbos: «me gustaría comprar una bici». El neerlandés manda el segundo verbo al final: «Ik zou graag een fiets kopen», nunca «Ik zou graag kopen een fiets». Es el error número uno del hispanohablante con «zou»."}, {"title": "«zou moet» no: tras «zou» va el infinitivo", "body": "Tras «zou», el otro verbo no se conjuga: se dice «Je zou moeten praten», no «Je zou moet praten». Y «zou» solo cambia por el número: zou en singular, zouden con wij, jullie y zij en plural."}, {"title": "«Ik zou graag…» pide su «willen»", "body": "La fórmula de cortesía completa es «Ik zou graag … willen» + infinitivo: «Ik zou graag twee kaartjes willen kopen». Sin «willen» la frase no es incorrecta, pero suena a deseo general y no a petición concreta en el mostrador."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál dice correctamente «me gustaría comprarme una bici nueva»?", "options": ["Ik zou graag een nieuwe fiets kopen.", "Ik zou graag kopen een nieuwe fiets.", "Ik graag zou een nieuwe fiets kopen."], "answer": "Ik zou graag een nieuwe fiets kopen.", "id": "u13q1"}, {"type": "cloze", "prompt": "Completa con el auxiliar que forma el condicional (sujeto en singular). No es el del futuro.", "text": "Wat ___ jij doen met zoveel geld?", "answer": "zou", "accepted": ["zou"], "id": "u13q2"}, {"type": "multiple_choice", "prompt": "¿Cuál da el consejo suave «deberías hablar con tu jefe»?", "options": ["Je zou met je baas moeten praten.", "Je zou moet met je baas praten.", "Je zou moeten met je baas praten."], "answer": "Je zou met je baas moeten praten.", "id": "u13q3"}, {"type": "cloze", "prompt": "Completa la fórmula fija de cortesía para pedir una cita por teléfono.", "text": "Ik zou graag een afspraak ___ maken voor volgende week.", "answer": "willen", "accepted": ["willen"], "id": "u13q4"}, {"type": "multiple_choice", "prompt": "¿Cuál dice «a mis padres también les gustaría venir»?", "options": ["Mijn ouders zouden ook graag willen komen.", "Mijn ouders zou ook graag willen komen.", "Mijn ouders zouden ook graag willen kom."], "answer": "Mijn ouders zouden ook graag willen komen.", "id": "u13q5"}]'::jsonb)
