insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 14, 'B1', 'Unir ideas: porque, aunque, así que', 'Sabrás mandar el verbo al final tras omdat, hoewel o zodat, distinguir omdat de want, e invertir la principal cuando la subordinada va delante.', '[{"heading": "El verbo se marcha al final: omdat ik moe ben", "body": "Con conjunciones como omdat, dat, hoewel, als, terwijl, voordat, nadat o zodat empieza una subordinada, y ahí el verbo conjugado deja su sitio habitual y cierra la frase. El español lo deja junto al sujeto; el neerlandés lo manda hasta el punto final.", "bullets": ["«Ik blijf thuis omdat ik moe ben»: ben cierra la frase.", "También con dat: «Ik denk dat hij morgen komt».", "Con dos verbos, los dos van al final: «…dat ik moet werken».", "Lo demás (objeto, tiempo, lugar) se coloca antes del verbo."]}, {"heading": "omdat o want: mismo «porque», distinta sintaxis", "body": "Omdat y want significan lo mismo, pero se comportan distinto. Omdat abre una subordinada y empuja el verbo al final; want une dos frases principales y no toca nada. Lo mismo hacen en, maar y «of» cuando significa «o»: detrás de ellas el orden sigue normal.", "bullets": ["«…, want ik ben ziek» frente a «…, omdat ik ziek ben».", "A la pregunta «Waarom?» se responde con Omdat…, no con Want.", "Con dus caben las dos: «dus ik ga» y «dus ga ik».", "«of» = si: «Ik weet niet of hij morgen komt» (verbo al final)."]}, {"heading": "Subordinada delante: la principal se invierte", "body": "La subordinada puede ir primera. Entonces ocupa ella sola el primer puesto de la frase, y como el verbo conjugado tiene que ser el segundo elemento, salta delante del sujeto: «Omdat het regent, blijf ik thuis». En español no ocurre nada de esto.", "bullets": ["«Als het mooi weer is, gaan we fietsen»: gaan antes de we.", "La coma marca el corte, pero lo que manda es el verbo.", "Sin invertir suena a extranjero: «Omdat het regent, ik blijf thuis».", "También con Hoewel, Terwijl, Nadat y Voordat al principio."]}]'::jsonb, '[{"nl": "We gaan niet fietsen omdat het buiten te koud is.", "es": "No vamos en bici porque fuera hace demasiado frío.", "text": "We gaan niet fietsen omdat het buiten te koud is.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0955109e-ddb3-59d8-9544-a59f8e9adc87.mp3"}, {"nl": "Ik ga niet mee, want ik moet vanavond werken.", "es": "No voy con vosotros, porque esta noche tengo que trabajar.", "text": "Ik ga niet mee, want ik moet vanavond werken.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8ac46ed2-3efd-5dba-9087-6e19c0098663.mp3"}, {"nl": "Omdat het hard regent, nemen we de tram.", "es": "Como llueve fuerte, cogemos el tranvía.", "text": "Omdat het hard regent, nemen we de tram.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e00aee74-2e22-5f5e-9f35-61fb45577d64.mp3"}, {"nl": "Ik schrijf het op zodat ik het niet vergeet.", "es": "Lo apunto para que no se me olvide.", "text": "Ik schrijf het op zodat ik het niet vergeet.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d8d66ade-ac9d-5f09-8590-4bf94812781f.mp3"}]'::jsonb, '[{"title": "«omdat ik ben moe» no: el verbo va al final", "body": "El calco del español coloca el verbo justo tras el sujeto. En neerlandés, detrás de omdat, dat, hoewel o terwijl el verbo conjugado se marcha al final: «omdat ik moe ben», «hoewel hij ziek is»."}, {"title": "Con want el orden se queda como está", "body": "Want no es subordinante: detrás de él la frase sigue igual que si fuera independiente, «want ik ben ziek». Si mueves el verbo al final tras want, o lo dejas delante tras omdat, la frase falla."}, {"title": "Tras la subordinada inicial, verbo antes del sujeto", "body": "«Omdat het regent, ik blijf thuis» es el error más repetido. La subordinada entera cuenta como primer elemento, así que el verbo de la principal va justo después de la coma: «…, blijf ik thuis»."}]'::jsonb, '[{"type": "cloze", "prompt": "Completa la subordinada con «tiempo» y el verbo «hebben», en el orden neerlandés (dos palabras).", "text": "Ik kom vanavond niet omdat ik geen ___.", "answer": "tijd heb", "accepted": ["tijd heb"], "id": "u14q1"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas frases es correcta?", "options": ["Ik ga niet mee, want ik ben ziek.", "Ik ga niet mee, want ik ziek ben.", "Ik ga niet mee, omdat ik ben ziek."], "answer": "Ik ga niet mee, want ik ben ziek.", "id": "u14q2"}, {"type": "multiple_choice", "prompt": "La subordinada va delante. ¿Cuál es la frase correcta?", "options": ["Omdat het regent, blijf ik thuis.", "Omdat het regent, ik blijf thuis.", "Omdat het regent, ik thuis blijf."], "answer": "Omdat het regent, blijf ik thuis.", "id": "u14q3"}, {"type": "cloze", "prompt": "Completa con la conjunción que significa «porque» y que NO cambia el orden (fíjate: el verbo no está al final).", "text": "Ik ga vanavond niet mee, ___ ik ben doodmoe.", "answer": "want", "accepted": ["want"], "id": "u14q4"}, {"type": "multiple_choice", "prompt": "¿Cuál coloca bien el verbo detrás de «zodat»?", "options": ["Ik zet de wekker zodat ik op tijd wakker word.", "Ik zet de wekker zodat ik word op tijd wakker.", "Ik zet de wekker zodat ik op tijd word wakker."], "answer": "Ik zet de wekker zodat ik op tijd wakker word.", "id": "u14q5"}]'::jsonb)
