insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 15, 'B1', 'Frases de relativo: die, dat, wie', 'Sabrás elegir die o dat según el artículo, mandar el verbo al final de la relativa y usar wat, met wie y waarin cuando die y dat no sirven.', '[{"heading": "«die» o «dat»: lo decide el artículo", "body": "El relativo español «que» se parte en dos en neerlandés y el artículo del antecedente decide cuál usar. Las palabras con de llevan die; las que llevan het usan dat. En plural todas las palabras llevan de, así que el relativo es siempre die.", "bullets": ["de-woorden: de man die belt, de tafel die daar staat.", "het-woorden: het boek dat ik lees, het kind dat slaapt.", "Plural siempre de, y por eso siempre die: de kinderen die hier wonen.", "Diminutivos llevan het: het huisje dat, het meisje dat slaapt."]}, {"heading": "El verbo de la relativa se va al final", "body": "La relativa es una subordinada, y en neerlandés el verbo conjugado cierra la frase. El español lo pone justo detrás de «que»; si lo copias, suena mal. Con tiempos compuestos, el auxiliar y el participio se van juntos al final.", "bullets": ["«De man die hier woont», no «de man die woont hier».", "Con objeto delante: «het boek dat ik gisteren kocht».", "Compuesto al final: «het huis dat we gekocht hebben».", "Si la relativa parte la frase, se suele cerrar con coma."]}, {"heading": "wat, met wie y waar-: cuando die/dat no valen", "body": "Después de alles, iets, niets y dat, el relativo es wat, y también cuando te refieres a toda la frase anterior. Con preposición, personas y cosas se separan: para personas usas met wie o voor wie; para cosas fusionas waar con la preposición.", "bullets": ["«Alles wat je zegt, klopt», «iets wat ik niet snap».", "Toda la frase: «Hij kwam te laat, wat vervelend was».", "Personas con preposición: «de collega met wie ik praat».", "Cosas: waarin, waarop, waarmee; en el habla, «waar ik op zit»."]}]'::jsonb, '[{"nl": "De man die daar staat, is mijn nieuwe baas.", "es": "El hombre que está allí es mi nuevo jefe.", "text": "De man die daar staat, is mijn nieuwe baas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/644f976d-82a8-58d6-b899-41a6d6d8d3f0.mp3"}, {"nl": "Het huis dat we gekocht hebben, is best oud.", "es": "La casa que hemos comprado es bastante vieja.", "text": "Het huis dat we gekocht hebben, is best oud.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8a1ee5d9-df51-5c00-818e-1391e86486d3.mp3"}, {"nl": "Alles wat hij over zijn baan vertelt, klinkt leuk.", "es": "Todo lo que cuenta sobre su empleo suena bien.", "text": "Alles wat hij over zijn baan vertelt, klinkt leuk.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ea1c8fcd-1638-59ca-9b72-9bff2275daff.mp3"}, {"nl": "De collega met wie ik werk, komt uit Utrecht.", "es": "El compañero con quien trabajo es de Utrecht.", "text": "De collega met wie ik werk, komt uit Utrecht.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/44fbe368-f7d1-5fab-a88d-aff59330f1f8.mp3"}]'::jsonb, '[{"title": "«het boek die» no existe: mira el artículo", "body": "Si el antecedente lleva het, el relativo es dat: het boek dat, het kind dat. Con de va die, y el plural siempre die. En el habla se oye «het meisje die» para personas, pero el estándar escrito es dat."}, {"title": "El verbo no se queda pegado al relativo", "body": "Calcar el español y decir «de man die woont hier» es el error más común. El verbo cierra la relativa: «de man die hier woont». Con perfecto, auxiliar y participio se van juntos: «het boek dat ik gelezen heb»."}, {"title": "«met die» no: met wie para personas", "body": "Detrás de una preposición, die y dat desaparecen. Con personas se usa wie: «de vrouw met wie ik werk». Con cosas se fusiona waar más preposición: «het huis waarin ik woon»; en el habla también «waar ik in woon»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es la frase correcta para «el libro que estoy leyendo»?", "options": ["het boek dat ik lees", "het boek die ik lees", "het boek dat lees ik"], "answer": "het boek dat ik lees", "id": "u15q1"}, {"type": "cloze", "prompt": "Completa con el relativo. Ojo: en singular sería «het kind», pero aquí el antecedente va en plural.", "text": "De kinderen ___ hiernaast wonen, zijn heel aardig.", "answer": "die", "accepted": ["die"], "id": "u15q2"}, {"type": "cloze", "prompt": "Completa con el relativo que se usa detrás de «alles».", "text": "Alles ___ je hier ziet, is te koop.", "answer": "wat", "accepted": ["wat"], "id": "u15q3"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «la mujer con la que trabajo»?", "options": ["de vrouw met wie ik werk", "de vrouw met die ik werk", "de vrouw die ik met werk"], "answer": "de vrouw met wie ik werk", "id": "u15q4"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta de «la casa en la que vivo»?", "options": ["het huis waarin ik woon", "het huis in dat ik woon", "het huis in wie ik woon"], "answer": "het huis waarin ik woon", "id": "u15q5"}]'::jsonb)
