insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 16, 'B1', 'La voz pasiva: worden + deelwoord', 'Sabrás formar la pasiva con «worden» más participio, llevarla al pasado con «werd», marcar el agente con «door» y distinguirla del resultado con «zijn».', '[{"heading": "La pasiva de acción: worden + participio", "body": "En la pasiva, lo que en la frase activa era el objeto pasa a ser el sujeto. El verbo «worden» se conjuga en segunda posición y el participio se marcha hasta el final de la frase, igual que en el perfecto.", "bullets": ["«Anna schrijft de brief» pasa a «De brief wordt geschreven».", "worden ocupa la segunda posición; el participio cierra la frase.", "Presente: ik word, jij wordt, hij wordt, wij worden.", "Sirve para la acción en curso: «Het huis wordt gebouwd»."]}, {"heading": "El agente con «door» y el pasado werd/werden", "body": "Quien hace la acción se marca con «door», y muchas veces ni se menciona porque no importa. En pasado, «worden» se convierte en «werd» con sujeto singular y en «werden» con sujeto plural; el participio sigue al final.", "bullets": ["«Het boek wordt door Anna gelezen»: door marca al agente.", "Sin agente también es correcto: «De brief wordt geschreven».", "Pasado singular: «De deur werd gesloten».", "Pasado plural: «De deuren werden gesloten»."]}, {"heading": "«zijn» + participio: el resultado, no la acción", "body": "«worden» presenta la acción mientras ocurre; «zijn» más participio presenta el resultado ya alcanzado. Por eso «De deur wordt gesloten» es «la están cerrando» y «De deur is gesloten» es «está cerrada». El perfecto de la pasiva usa también «is/zijn» y en los Países Bajos deja fuera «geworden».", "bullets": ["«De winkel is gesloten»: ya está cerrada, es el resultado.", "Perfecto de pasiva: «Het huis is gebouwd», sin «geworden».", "El español usa ser/estar; aquí eliges entre worden y zijn.", "«is + participio» se lee como acción pasada solo con marca de tiempo."]}]'::jsonb, '[{"nl": "De brief wordt vandaag nog geschreven.", "es": "La carta se escribe hoy mismo.", "text": "De brief wordt vandaag nog geschreven.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9ee684e1-d568-5048-a782-6cb93b4a9c64.mp3"}, {"nl": "Het boek wordt door Anna gelezen.", "es": "El libro es leído por Anna.", "text": "Het boek wordt door Anna gelezen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/52a6f513-c554-5599-8263-62210087c3d5.mp3"}, {"nl": "De deuren werden om zes uur gesloten.", "es": "Las puertas fueron cerradas a las seis.", "text": "De deuren werden om zes uur gesloten.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f559604e-abc6-52dd-96b9-ff6865d3c96f.mp3"}, {"nl": "Het huis is in 1980 gebouwd.", "es": "La casa fue construida en 1980.", "text": "Het huis is in 1980 gebouwd.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/247d0f7a-d166-5bd9-9be3-208907b0fa42.mp3"}]'::jsonb, '[{"title": "«is geschreven» no es «se está escribiendo»", "body": "El español usa ser y estar para las dos cosas. En neerlandés, la acción en curso pide «worden»: «De brief wordt geschreven». Con «zijn» aparece el resultado: «De brief is geschreven» significa que ya está escrita."}, {"title": "El participio va al final, no junto al verbo", "body": "Calcar el español y decir «De brief wordt geschreven vandaag» deja el participio a medias. En neerlandés, «worden» va en segunda posición y el participio cierra la frase (solo un grupo con preposición puede quedar detrás: «geschreven door Anna»): «De brief wordt vandaag door Anna geschreven»."}, {"title": "El agente va con «door», no con «van»", "body": "Quien hace la acción se introduce con «door»: «Het boek wordt door Anna gelezen». Calcar el «por» español con «van» o «bij» suena mal. Y recuerda que el agente se puede omitir sin problema."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo dices que la carta se está escribiendo ahora, como acción en curso?", "options": ["De brief wordt geschreven.", "De brief is geschreven.", "De brief wordt schrijven."], "answer": "De brief wordt geschreven.", "id": "u16q1"}, {"type": "cloze", "prompt": "Completa con el verbo de la pasiva en presente. Fíjate en que el sujeto es plural.", "text": "De ramen ___ elke week schoongemaakt.", "answer": "worden", "accepted": ["worden"], "id": "u16q2"}, {"type": "cloze", "prompt": "Completa con «worden» en pasado. El sujeto es singular.", "text": "Toen ik binnenkwam, ___ de deur door de bewaker gesloten.", "answer": "werd", "accepted": ["werd"], "id": "u16q3"}, {"type": "cloze", "prompt": "Completa con la preposición que introduce a quien hace la acción.", "text": "Het boek wordt ___ Anna gelezen.", "answer": "door", "accepted": ["door"], "id": "u16q4"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas frases coloca bien el verbo y el participio?", "options": ["De brief wordt vandaag door Anna geschreven.", "De brief wordt geschreven vandaag door Anna.", "Vandaag de brief wordt door Anna geschreven."], "answer": "De brief wordt vandaag door Anna geschreven.", "id": "u16q5"}]'::jsonb)
