insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 17, 'B1', 'Verbos con preposición fija y «om … te»', 'Sabrás usar la preposición que exige cada verbo (wachten op, denken aan) y decir para qué haces algo con «om … te», también con verbos separables.', '[{"heading": "La preposición viene pegada al verbo", "body": "En neerlandés cada verbo arrastra su propia preposición y casi nunca coincide con la española. «Pensar en» es denken aan, «esperar a» es wachten op y «gustar» es houden van. No la deduzcas: apréndela pegada al verbo, como el artículo de un sustantivo.", "bullets": ["wachten op, denken aan, kijken naar, luisteren naar, zoeken naar.", "houden van, praten over, beginnen met, helpen met.", "También con adjetivos: bang zijn voor, blij zijn met.", "La preposición no se traduce: memorízala junto con el verbo."]}, {"heading": "«om … te»: decir para qué haces algo", "body": "Para expresar el propósito pones «om» delante del complemento y «te» justo antes del infinitivo, que se marcha al final: «Ik ga naar de winkel om brood te kopen». El español coloca el infinitivo enseguida («voy a comprar pan»); el neerlandés lo deja para el final.", "bullets": ["«Ik leer Nederlands om in Amsterdam te werken».", "Todo lo demás va entre «om» y «te»: om brood te kopen.", "Con verbo separable, «te» se mete dentro: om af te spreken.", "En frases de propósito «om» siempre vale; con hopen/proberen no se pone."]}, {"heading": "«erop», «eraan»: cuando es una cosa", "body": "Cuando el complemento de la preposición es una cosa ya sabida, no repites «het» ni «dat»: se funde con «er». Wachten op → ik wacht erop; denken aan → ik denk eraan. Con «met» la forma cambia a ermee. De personas, en cambio, sí dices op hem, aan haar.", "bullets": ["Ik denk aan het werk → Ik denk eraan.", "Con met la forma es «mee»: ermee, no «ermet».", "De personas no se usa «er»: ik denk aan hem.", "Si hay algo en medio, se separan: «Ik wacht er al tien minuten op»."]}]'::jsonb, '[{"nl": "We wachten al een half uur op de bus.", "es": "Llevamos ya media hora esperando el autobús.", "text": "We wachten al een half uur op de bus.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/143ffbd8-3e7b-5dd0-b25b-295037e68c1e.mp3"}, {"nl": "Ik ga naar de winkel om brood te kopen.", "es": "Voy a la tienda a comprar pan.", "text": "Ik ga naar de winkel om brood te kopen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8ea61337-f9bd-5509-9a6c-262f8330068c.mp3"}, {"nl": "Ik bel je vanavond op om iets af te spreken.", "es": "Te llamo esta noche para quedar en algo.", "text": "Ik bel je vanavond op om iets af te spreken.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1ddec8c1-e9b7-5575-a5a1-eeb4e85bcb75.mp3"}, {"nl": "Denk je aan de vergadering? Ja, ik denk eraan.", "es": "¿Te acuerdas de la reunión? Sí, me acuerdo.", "text": "Denk je aan de vergadering? Ja, ik denk eraan.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/aa25e19d-1779-5045-8823-737bd6dac762.mp3"}]'::jsonb, '[{"title": "«denken in» no existe: es «denken aan»", "body": "El error número uno es traducir la preposición española. «Pienso en ti» no es ik denk in jou, sino «ik denk aan jou»; «espero el autobús» es «ik wacht op de bus». La preposición forma parte del verbo, no del significado literal."}, {"title": "Con verbo separable, el «te» va en medio", "body": "«Opbellen» no da om te opbellen: el «te» parte el verbo y queda «om je op te bellen». Lo mismo con meegaan (om mee te gaan). Si el verbo no es separable, «te» va delante: om te werken."}, {"title": "No «ik wacht op het», sino «ik wacht erop»", "body": "Con una cosa ya mencionada, el neerlandés no pone el pronombre detrás de la preposición: no ik wacht op het, sino «ik wacht erop». Con «met» la forma es «ermee». Si hablas de una persona sí vale: «ik wacht op hem»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «pienso mucho en mi familia»?", "options": ["Ik denk vaak aan mijn familie.", "Ik denk vaak in mijn familie.", "Ik denk vaak op mijn familie."], "answer": "Ik denk vaak aan mijn familie.", "id": "u17q1"}, {"type": "cloze", "prompt": "Completa con la preposición fija que pide el verbo de la frase.", "text": "We wachten al tien minuten ___ de tram.", "answer": "op", "accepted": ["op"], "id": "u17q2"}, {"type": "multiple_choice", "prompt": "¿Cuál es la frase correcta para «Te llamo esta noche para quedar»?", "options": ["Ik bel je vanavond op om af te spreken.", "Ik bel je vanavond op om te afspreken.", "Ik bel je vanavond om af te spreken op."], "answer": "Ik bel je vanavond op om af te spreken.", "id": "u17q3"}, {"type": "cloze", "prompt": "Completa con la palabra que introduce el propósito («para»).", "text": "Ik ga naar de bakker ___ brood te kopen.", "answer": "om", "accepted": ["om"], "id": "u17q4"}, {"type": "multiple_choice", "prompt": "«Denk je aan de vergadering?» ¿Cuál es la respuesta correcta?", "options": ["Ja, ik denk eraan.", "Ja, ik denk aan het.", "Ja, ik denk aan dat."], "answer": "Ja, ik denk eraan.", "id": "u17q5"}]'::jsonb)
