insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 18, 'B1', 'Lo que ya había pasado y lo que habría pasado', 'Sabrás contar lo anterior a otro momento del pasado con «had» o «was» + participio, y decir lo que habría pasado con «zou … gedaan hebben».', '[{"heading": "El pluscuamperfecto: had/was + participio", "body": "Para contar lo que ya había pasado antes de otro momento del pasado usas «had» o «was» más el participio: Ik had het boek al gelezen. El auxiliar va en segunda posición y el participio cierra la frase, igual que en el perfectum.", "bullets": ["Formas: ik/hij had, wij hadden; ik/hij was, wij waren.", "«Ik had het boek al gelezen» = ya lo había leído.", "«Zij was al vertrokken» = ella ya se había marchado.", "El participio se marcha al final, como en el perfectum."]}, {"heading": "El auxiliar es el mismo que en el perfectum", "body": "Si el verbo forma el perfectum con hebben, el pluscuamperfecto usa had; si lo forma con zijn, usa was. Los verbos de movimiento y de cambio siguen con zijn: gaan, komen, vertrekken, blijven, worden. Aparece sobre todo tras nadat, toen y con al.", "bullets": ["Con hebben: ik had gewerkt, gelezen, gegeten, gekocht.", "Con zijn: ik was gegaan, gekomen, vertrokken, gebleven.", "«Nadat we gegeten hadden, gingen we naar huis.»", "Con «al» marcas que la cosa ya estaba hecha antes."]}, {"heading": "Lo que habría pasado: zou hebben/zijn + participio", "body": "Para lo que habría ocurrido y no ocurrió usas zou más el participio y hebben o zijn: Ik zou het gedaan hebben. El auxiliar que eliges es el mismo de siempre. Al final se amontonan dos o tres verbos, algo que el español nunca hace.", "bullets": ["«Ik zou het anders gedaan hebben» = lo habría hecho distinto.", "«Dat zou beter geweest zijn» pide zijn, no hebben.", "También vale «zou hebben gedaan»: las dos órdenes son correctas.", "El objeto nunca se cuela entre zou y los verbos finales."]}]'::jsonb, '[{"nl": "Ik had het boek al gelezen toen je het vertelde.", "es": "Ya había leído el libro cuando me lo contaste.", "text": "Ik had het boek al gelezen toen je het vertelde.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/59002a90-a6c5-5b54-948e-2f09c5f458d8.mp3"}, {"nl": "Nadat we gegeten hadden, zijn we naar huis gegaan.", "es": "Después de comer, nos fuimos a casa.", "text": "Nadat we gegeten hadden, zijn we naar huis gegaan.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a5dae101-3d5b-5480-aa56-167155b3cfd2.mp3"}, {"nl": "De trein was al vertrokken toen ik aankwam.", "es": "El tren ya había salido cuando llegué.", "text": "De trein was al vertrokken toen ik aankwam.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/381316fb-3d23-571b-8b42-30b38b35556b.mp3"}, {"nl": "Ik zou het anders gedaan hebben.", "es": "Yo lo habría hecho de otra manera.", "text": "Ik zou het anders gedaan hebben.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f42f24d6-aed9-5e1a-9b9f-266fdb38cfb5.mp3"}]'::jsonb, '[{"title": "«había» no siempre se dice «had»", "body": "El español usa siempre «haber», así que sale solo «ik had gegaan». Con verbos de movimiento o de cambio el auxiliar es zijn: «ik was gegaan», «de trein was vertrokken», «zij was gebleven». Elige el mismo auxiliar que usarías en el perfectum."}, {"title": "El participio cierra la frase", "body": "En español el participio sigue al auxiliar: «ya había leído el libro». En neerlandés el auxiliar queda en segunda posición y el participio se marcha al final: «Ik had het boek al gelezen», nunca «Ik had gelezen het boek»."}, {"title": "«zou hebben het gedaan» no existe", "body": "Con el condicional pasado los verbos se agrupan al final: «Ik zou het anders gedaan hebben» o «Ik zou het anders hebben gedaan». Las dos órdenes valen, pero el objeto («het») nunca puede colarse entre zou y los verbos."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Qué frase dice «ya había leído el libro», antes de otro momento del pasado?", "options": ["Ik had het boek al gelezen.", "Ik heb het boek al gelezen.", "Ik was het boek al gelezen."], "answer": "Ik had het boek al gelezen.", "id": "u18q1"}, {"type": "cloze", "prompt": "Completa con el auxiliar en pasado que le corresponde a este verbo. Una sola palabra.", "text": "Toen ik op het station aankwam, ___ de trein al vertrokken.", "answer": "was", "accepted": ["was"], "id": "u18q2"}, {"type": "multiple_choice", "prompt": "¿Qué frase dice bien «lo habría hecho de otra manera»?", "options": ["Ik zou het anders gedaan hebben.", "Ik zou hebben het anders gedaan.", "Ik zou het anders doen hebben."], "answer": "Ik zou het anders gedaan hebben.", "id": "u18q3"}, {"type": "cloze", "prompt": "Completa con el participio del verbo que significa «comer».", "text": "Nadat we ___ hadden, gingen we naar huis.", "answer": "gegeten", "accepted": ["gegeten"], "id": "u18q4"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «eso habría sido mejor»?", "options": ["Dat zou beter geweest zijn.", "Dat zou beter geweest hebben.", "Dat had beter geweest."], "answer": "Dat zou beter geweest zijn.", "id": "u18q5"}]'::jsonb)
