  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 19, 'B2', 'Estilo indirecto: contar lo que otro dijo', 'Sabrás contar lo que alguien dijo o preguntó: «dat» con el verbo al final, los tiempos que retroceden y «of» para las preguntas de sí o no.', '[{"heading": "«Hij zei dat…»: el verbo se va al final", "body": "Para contar lo que alguien dijo usas «zeggen dat» seguido de una subordinada. Dentro de ella el verbo conjugado deja la segunda posición y se coloca al final, detrás de los complementos. Si hay dos verbos, los dos cierran la frase juntos.", "bullets": ["«Hij zei dat ze in Utrecht woont»: el verbo cierra.", "Con dos verbos, ambos van al final: «…dat ze wilde komen».", "El sujeto va justo detrás de «dat», nunca detrás del verbo.", "Vertellen, denken y antwoorden funcionan igual que zeggen."]}, {"heading": "Los tiempos retroceden al contar en pasado", "body": "Cuando el verbo introductor está en pasado, lo dicho retrocede un paso: el presente pasa a imperfectum, el perfectum a «had» o «was» más participio, y «zal» a «zou». Si lo contado sigue siendo verdad hoy, muchos hablantes mantienen el presente.", "bullets": ["«Ik werk hier» → Hij zei dat hij hier werkte.", "«Ik heb gebeld» → Hij zei dat hij gebeld had.", "«Ik zal komen» → Hij zei dat hij zou komen.", "Si lo dicho sigue vigente, también se oye el presente."]}, {"heading": "Preguntas, órdenes y palabras que se mueven", "body": "Las preguntas reportadas también llevan el verbo al final. Las de sí o no empiezan por «of»; las demás conservan su palabra interrogativa. Las órdenes se cuentan con «om … te» más infinitivo, y los adverbios de tiempo y lugar se desplazan al momento del relato.", "bullets": ["Pregunta de sí o no: «Ze vroeg of ik tijd had».", "Con interrogativa: «Hij vroeg waar ik woonde».", "Orden reportada: «Ze vroeg me om de deur te sluiten».", "nu → toen, hier → daar, morgen → de volgende dag."]}]'::jsonb, '[{"nl": "Hij zei dat hij het boek al gelezen had.", "es": "Dijo que ya había leído el libro.", "text": "Hij zei dat hij het boek al gelezen had.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2da94170-0f86-5319-a53b-d2c82d7cd92f.mp3"}, {"nl": "Ze vroeg of ik zin had in koffie.", "es": "Preguntó si me apetecía un café.", "text": "Ze vroeg of ik zin had in koffie.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/aaef1138-6785-5e03-8865-c1b9be4731b3.mp3"}, {"nl": "Hij vroeg wanneer de vergadering zou beginnen.", "es": "Preguntó cuándo empezaría la reunión.", "text": "Hij vroeg wanneer de vergadering zou beginnen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/19fba93d-fe2a-56e9-af5d-62f13d0d53ec.mp3"}, {"nl": "Ze zei dat ze de volgende dag zou bellen.", "es": "Dijo que llamaría al día siguiente.", "text": "Ze zei dat ze de volgende dag zou bellen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9e0f609d-5fe1-5a64-b480-8bccf0d433ba.mp3"}]'::jsonb, '[{"title": "«of» pregunta, «als» pone una condición", "body": "El «si» del español es una sola palabra; el neerlandés tiene dos. En una pregunta indirecta de sí o no va «of»: Ze vroeg of ik kwam. «Als» solo introduce una condición: Als ik kom, bel ik je."}, {"title": "El verbo no se queda en medio de la frase", "body": "Tras «dat» el verbo conjugado viaja hasta el final. «Hij zei dat hij was moe» calca el orden español y suena mal; lo correcto es «Hij zei dat hij moe was». Con dos verbos, los dos cierran la frase."}, {"title": "«zal» → «zou» y los adverbios que se mueven", "body": "Al contar en pasado, «zal» se convierte en «zou» y los adverbios se mueven con el relato: nu → toen, morgen → de volgende dag. «Hij zei dat hij morgen zal komen» mezcla un adverbio ya desplazado con un tiempo sin desplazar; si lo contado sigue vigente, el presente es normal; di «…dat hij de volgende dag zou komen»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Qué frase cuenta bien «No lo sé», dicho por él?", "options": ["Hij zei dat hij het niet wist.", "Hij zei dat hij wist het niet.", "Hij zei dat hij weet het niet."], "answer": "Hij zei dat hij het niet wist.", "id": "u19q1"}, {"type": "cloze", "prompt": "Completa la pregunta indirecta de sí o no. Ojo: el «si» de pregunta y el «si» de condición son dos palabras distintas en neerlandés.", "text": "Ze vroeg ___ ik naar het feest meeging.", "answer": "of", "accepted": ["of"], "id": "u19q2"}, {"type": "multiple_choice", "prompt": "«Ik heb de mail al gestuurd», zei Tom. Al contarlo en pasado: «Tom zei dat hij de mail al ___ gestuurd.»", "options": ["had", "hadden", "was"], "answer": "had", "id": "u19q3"}, {"type": "cloze", "prompt": "«Ik bel je morgen», beloofde hij. Completa el hueco con la forma que sustituye al futuro cuando cuentas la promesa en pasado.", "text": "Hij beloofde dat hij me de volgende dag ___ bellen.", "answer": "zou", "accepted": ["zou"], "id": "u19q4"}, {"type": "cloze", "prompt": "Completa con el adverbio que, en un relato en pasado, sustituye a «ahora».", "text": "Hij zei dat hij ___ geen tijd had.", "answer": "toen", "accepted": ["toen", "op dat moment", "destijds"], "id": "u19q5"}]'::jsonb)
