insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 20, 'B2', 'Pasiva avanzada: modales y el «er» impersonal', 'Sabrás construir la pasiva con moeten, kunnen y mogen, decir «se baila» con «er wordt gedanst» y cerrar el perfecto sin «geworden».', '[{"heading": "Pasiva con modal: moet ingevuld worden", "body": "Con un modal, la pasiva pide tres piezas: el modal conjugado en segunda posición, el participio y el infinitivo «worden» cerrando la frase. Los dos órdenes finales son igual de correctos: «moet ingevuld worden» y «moet worden ingevuld».", "bullets": ["«Het formulier moet ingevuld worden» = «el formulario debe rellenarse».", "«worden» va en infinitivo, nunca conjugado: no «moet ingevuld wordt».", "Con kan y mag igual: «Dit kan online gedaan worden».", "También vale el otro orden: «Dit moet worden gedaan»."]}, {"heading": "Pasiva impersonal: Er wordt gedanst", "body": "El neerlandés puede pasivizar un verbo sin objeto: nadie hace de sujeto. Como la frase necesita algo en ese hueco, entra «er», una palabra vacía sin traducción: «Er wordt gedanst». El español lo resuelve con «se baila» o «hay baile».", "bullets": ["«Er wordt gebeld»: llaman a la puerta o suena el teléfono.", "En pasado: «Er werd veel gelachen» = «se rió mucho».", "Si otro elemento abre la frase, «er» pasa detrás del verbo.", "«Gisteren werd er hard gewerkt»; a veces «er» se omite ahí."]}, {"heading": "Perfecto de la pasiva, door y met", "body": "El perfecto de la pasiva se hace con «zijn» + participio, y ahí «geworden» desaparece: «Het huis is gebouwd», nunca «is gebouwd geworden». Para el autor de la acción usas «door»; para el instrumento, «met». El pasado simple sigue con «werd».", "bullets": ["Perfecto: «De brief is al verstuurd» (la carta ya se envió).", "El autor va con door: «door de politie», «door mijn opa».", "La herramienta va con met: «met een sleutel», «met een steen».", "Pluscuamperfecto: «Het huis was al verkocht», tampoco con geworden."]}]'::jsonb, '[{"nl": "Dit formulier moet vandaag nog ingevuld worden.", "es": "Este formulario tiene que rellenarse hoy mismo.", "text": "Dit formulier moet vandaag nog ingevuld worden.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e9dc278b-d096-53fd-bd74-4bbcffb2111c.mp3"}, {"nl": "Er wordt vanavond op het plein gedanst.", "es": "Esta noche se baila en la plaza.", "text": "Er wordt vanavond op het plein gedanst.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/94d25ce1-1b40-54f8-93a1-4e8240016ca2.mp3"}, {"nl": "Op het feest werd er veel gelachen.", "es": "En la fiesta se rió mucho.", "text": "Op het feest werd er veel gelachen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fdda7574-171e-5bda-972d-ac1afc246542.mp3"}, {"nl": "Het huis is in 1918 door mijn overgrootvader gebouwd.", "es": "La casa fue construida en 1918 por mi bisabuelo.", "text": "Het huis is in 1918 door mijn overgrootvader gebouwd.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b5365b58-3fe4-54a1-ba6d-9f9dd5a18d74.mp3"}]'::jsonb, '[{"title": "«moet ingevuld wordt» no: worden en infinitivo", "body": "El modal ya está conjugado, así que «worden» se queda en infinitivo y cierra la frase: «Het formulier moet ingevuld worden». También vale «moet worden ingevuld». Lo agramatical es «moet ingevuld wordt» o poner el infinitivo «invullen» en lugar del participio."}, {"title": "Sin «er» la pasiva impersonal no se sostiene", "body": "El español dice «se baila» sin más; el neerlandés necesita un sujeto formal. Si nada abre la frase, «er» es obligatorio: «Er wordt gedanst». Ni «Het wordt gedanst» ni un reflexivo calcado del español funcionan aquí."}, {"title": "«gebouwd geworden» sobra: fuera el geworden", "body": "En el perfecto de la pasiva el neerlandés suelta el participio de worden: «Het huis is gebouwd». Añadir «geworden» es un calco del alemán y suena mal. Y el auxiliar es «zijn», no «hebben»: «heeft gebouwd» solo sirve en activa."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta de «el formulario debe rellenarse»?", "options": ["Het formulier moet ingevuld worden.", "Het formulier moet ingevuld wordt.", "Het formulier moet invullen worden."], "answer": "Het formulier moet ingevuld worden.", "id": "u20q1"}, {"type": "cloze", "prompt": "Completa la pasiva impersonal: falta la palabrita vacía que ocupa el sitio del sujeto.", "text": "___ wordt vanavond in het dorpshuis gedanst.", "answer": "er", "accepted": ["er"], "id": "u20q2"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «la casa fue construida en 1920», como hecho ya terminado?", "options": ["Het huis is in 1920 gebouwd.", "Het huis is in 1920 gebouwd geworden.", "Het huis heeft in 1920 gebouwd."], "answer": "Het huis is in 1920 gebouwd.", "id": "u20q3"}, {"type": "cloze", "prompt": "Completa con la preposición del instrumento (la herramienta usada), no con la del autor de la acción.", "text": "De deur werd ___ een oude sleutel geopend.", "answer": "met", "accepted": ["met"], "id": "u20q4"}, {"type": "cloze", "prompt": "Completa con el verbo que forma la pasiva de acción, en la forma que exige el modal «kan».", "text": "Het formulier kan ook online ingevuld ___.", "answer": "worden", "accepted": ["worden"], "id": "u20q5"}]'::jsonb)
