  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 21, 'B2', 'El participio como adjetivo: slapend, gesloten', 'Sabrás usar el participio como adjetivo: de slapende baby frente a de gesloten deur, con o sin -e, y leer de door Anna geschreven brief.', '[{"heading": "-end dice qué hace; ge-...-en, qué le han hecho", "body": "El participio en -end (infinitivo más d) describe lo que el sustantivo hace: de slapende baby. El participio pasado describe lo que le han hecho o el estado en que quedó: de gesloten deur, het gebroken glas. Con verbos como vallen expresa el resultado, no la voz pasiva.", "bullets": ["slapen → slapend: de slapende baby, el bebé que duerme.", "sluiten → gesloten: de gesloten deur, la puerta cerrada.", "Se forma con el infinitivo más -d: huilen → huilend.", "Con vallen: de gevallen bladeren, las hojas caídas."]}, {"heading": "La -e: het slapende kind, het gebroken been", "body": "La -e sigue la regla del adjetivo: se pone casi siempre, y solo desaparece ante un het-woord singular con een, geen o sin artículo (gekookt water). Los participios acabados en -en son la excepción: gebroken, gesloten y geschreven no cambian nunca. Los acabados en -d o -t sí: de gerepareerde fiets.", "bullets": ["Con de, -e salvo los participios en -en: de slapende baby, de gesloten deur.", "het slapende kind lleva -e; een slapend kind, no.", "gebroken, gesloten y geschreven acaban en -en: nunca toman -e.", "een gebroken been y het gebroken been: forma idéntica."]}, {"heading": "De door Anna geschreven brief: la fórmula escrita", "body": "En textos escritos el participio arrastra sus complementos y todo el bloque se mete entre el artículo y el sustantivo: de door Anna geschreven brief. Se lee de dentro afuera. Al hablar se prefiere una relativa: de brief die Anna geschreven heeft.", "bullets": ["de door Anna geschreven brief: la carta escrita por Anna.", "El autor entra con door, dentro del bloque, no detrás.", "También con -end: de in de tuin spelende kinderen.", "Al hablar: de brief die Anna geschreven heeft."]}]'::jsonb, '[{"nl": "Wees stil, anders wordt de slapende baby wakker.", "es": "Habla bajo, si no el bebé que duerme se despierta.", "text": "Wees stil, anders wordt de slapende baby wakker.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4095405e-9c51-5baf-9906-4b3f01c76246.mp3"}, {"nl": "Er ligt een gebroken glas op de grond.", "es": "Hay un vaso roto en el suelo.", "text": "Er ligt een gebroken glas op de grond.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/660bb84b-495a-5472-ae49-28dbe869622c.mp3"}, {"nl": "Achter die gesloten deur zit een huilend kind.", "es": "Detrás de esa puerta cerrada hay un niño llorando.", "text": "Achter die gesloten deur zit een huilend kind.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/05e5bbdb-4286-5a36-997f-f7f4fc3aac6c.mp3"}, {"nl": "De door Anna geschreven brief ligt op mijn bureau.", "es": "La carta escrita por Anna está sobre mi escritorio.", "text": "De door Anna geschreven brief ligt op mijn bureau.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4eef38f6-dc6c-54d9-854d-0ea508c9f0e4.mp3"}]'::jsonb, '[{"title": "«Ik ben werkend» no existe en neerlandés", "body": "El -end no traduce el gerundio español: «estoy trabajando» no es «ik ben werkend», sino «ik ben aan het werken» o «ik zit te werken». El participio en -end vive delante del sustantivo, como adjetivo: de werkende man."}, {"title": "«de geslotene deur»: gesloten no lleva -e", "body": "Después de aprender «de grote man» es tentador poner -e a todo. Los participios acabados en -en no la aceptan: de gesloten deur, het gebroken glas, de geschreven brief. Los acabados en -d o -t sí: de gekookte aardappelen."}, {"title": "El bloque va delante, no detrás del sustantivo", "body": "El español pone el participio detrás: «la carta escrita por Anna». En neerlandés todo el bloque cabe entre el artículo y el sustantivo: de door Anna geschreven brief; «de brief door Anna geschreven» no funciona como atributo desnudo (entre comas sí: «de brief, geschreven door Anna, lag op tafel»). Al hablar, usa una relativa."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «un niño que llora»? (het kind)", "options": ["een huilend kind", "een huilende kind", "een kind huilend"], "answer": "een huilend kind", "id": "u21q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta de «la puerta cerrada»?", "options": ["de gesloten deur", "de geslotene deur", "de sluitende deur"], "answer": "de gesloten deur", "id": "u21q2"}, {"type": "multiple_choice", "prompt": "«Los niños que juegan hacen mucho ruido.» ¿Cuál frase es neerlandés correcto?", "options": ["De spelende kinderen maken veel lawaai.", "De spelend kinderen maken veel lawaai.", "De kinderen spelende maken veel lawaai."], "answer": "De spelende kinderen maken veel lawaai.", "id": "u21q3"}, {"type": "cloze", "prompt": "Completa con la preposición que introduce a la persona que hizo la acción, dentro del bloque.", "text": "Anna heeft de brief zelf geschreven. De ___ Anna geschreven brief ligt op mijn bureau.", "answer": "door", "accepted": ["door"], "id": "u21q4"}, {"type": "cloze", "prompt": "El neerlandés no usa la forma en -end para «estar + gerundio». Completa las dos palabras que faltan.", "text": "Stoor hem niet: hij is ___ werken.", "answer": "aan het", "accepted": ["aan het", "bezig met", "bezig te"], "id": "u21q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000006', 22, 'B2', 'Conectores cultos: niettemin, zowel… als', 'Sabrás enlazar ideas con niettemin o daarentegen sin romper el orden del verbo, y usar los pares zowel… als, noch… noch y enerzijds… anderzijds.', '[{"heading": "Niettemin y compañía empujan el verbo", "body": "Niettemin, desondanks, daarentegen, bovendien, vervolgens y derhalve son adverbios, no conjunciones. Cuando abren la frase ocupan la primera posición, así que el verbo conjugado tiene que ir inmediatamente después y el sujeto se desplaza detrás de él. Es el orden que el español no exige.", "bullets": ["«Het regende; niettemin ging hij naar buiten»: verbo antes del sujeto.", "Desondanks y niettemin equivalen a «aun así, pese a ello».", "Bovendien añade («además»); vervolgens ordena («a continuación»).", "Derhalve («por tanto») pertenece al registro escrito muy formal."]}, {"heading": "Pares fijos: zowel… als, noch… noch", "body": "El neerlandés une elementos con parejas fijas que conviene no mezclar. «Zowel … als» equivale a «tanto… como»; «noch … noch» significa «ni… ni» y ya lleva la negación dentro, así que no añades geen ni niet. «Niet alleen … maar ook» y «enerzijds … anderzijds» completan el grupo.", "bullets": ["«Ze spreekt zowel Frans als Duits»: tanto… como.", "«Ik drink noch koffie noch thee»: la negación ya está dentro.", "«Niet alleen duur, maar ook slecht»: no solo… sino también.", "«Enerzijds… anderzijds» sirve para sopesar dos lados de algo."]}, {"heading": "hoewel manda el verbo al final; echter no", "body": "Hoewel y ofschoon sí son conjunciones subordinantes: la frase que abren manda el verbo conjugado al final («hoewel het regende»). Maar y echter, en cambio, no subordinan nada. Echter suele colocarse dentro de la frase, detrás del sujeto o del verbo, no abriéndola.", "bullets": ["«Hoewel ik moe ben, ga ik toch mee»: verbo al final.", "Con la subordinada delante, la principal invierte: «…, ga ik mee».", "Ofschoon significa lo mismo que hoewel, pero suena más formal.", "«Echter,» al principio se ve por escrito, pero muchos lo desaconsejan."]}]'::jsonb, '[{"nl": "Het weer was slecht; niettemin gingen we op de fiets.", "es": "El tiempo era malo; aun así fuimos en bici.", "text": "Het weer was slecht; niettemin gingen we op de fiets.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/458a3895-d51e-55b9-b45a-c7fb3ed246e4.mp3"}, {"nl": "Zowel de directeur als de werknemers waren het ermee eens.", "es": "Tanto el director como los empleados estaban de acuerdo.", "text": "Zowel de directeur als de werknemers waren het ermee eens.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/79bf3022-b855-5384-bfab-1cf0619d4fac.mp3"}, {"nl": "Hoewel hij hard gestudeerd had, zakte hij voor het examen.", "es": "Aunque había estudiado mucho, suspendió el examen.", "text": "Hoewel hij hard gestudeerd had, zakte hij voor het examen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3e6c4e1f-f8f4-516e-86dd-86cd0b83fe6d.mp3"}, {"nl": "Ik wilde je bellen; ik had echter geen bereik.", "es": "Quería llamarte; sin embargo, no tenía cobertura.", "text": "Ik wilde je bellen; ik had echter geen bereik.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b7b223da-bc71-56b3-944d-5da4a59847aa.mp3"}]'::jsonb, '[{"title": "«Niettemin hij ging»: falta la inversión", "body": "En español «sin embargo» no toca el verbo, y por eso se calca *«Niettemin hij ging naar buiten». Al abrir la frase, niettemin ocupa la primera casilla y el verbo conjugado la segunda: «Niettemin ging hij naar buiten». Lo mismo con desondanks, daarentegen y bovendien."}, {"title": "«zowel… en» no existe: la pieza es «als»", "body": "Traducir «tanto X como Y» con en es el fallo más repetido: *«zowel Spaans en Nederlands». La segunda pieza es als (en registro formal también alsook). Y con noch… noch la negación ya va dentro: no añadas geen ni niet."}, {"title": "hoewel no es maar: el verbo cierra la frase", "body": "«Hoewel» abre una subordinada y el verbo conjugado cierra esa frase: «hoewel ik moe was». Decir *«hoewel ik was moe» calca el español. Echter, en cambio, no abre nada: va dentro de la frase, «ik had echter geen tijd»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Qué frase coloca bien el verbo tras el conector inicial?", "options": ["Het was koud; niettemin gingen we naar buiten.", "Het was koud; niettemin we gingen naar buiten.", "Het was koud; niettemin we naar buiten gingen."], "answer": "Het was koud; niettemin gingen we naar buiten.", "id": "u22q1"}, {"type": "cloze", "prompt": "Completa la segunda pieza del par que traduce «tanto… como».", "text": "Ze spreekt zowel Spaans ___ Nederlands, dus ze kan overal werken.", "answer": "als", "accepted": ["als", "alsook"], "id": "u22q2"}, {"type": "multiple_choice", "prompt": "¿Cuál respeta el orden que exige «hoewel»?", "options": ["Hoewel ik moe was, ben ik toch gekomen.", "Hoewel ik was moe, ben ik toch gekomen.", "Hoewel ik moe was, ik ben toch gekomen."], "answer": "Hoewel ik moe was, ben ik toch gekomen.", "id": "u22q3"}, {"type": "cloze", "prompt": "Completa el conector que cierra el par «por un lado… por otro».", "text": "Enerzijds wil ik in Nederland blijven, ___ mis ik mijn familie.", "answer": "anderzijds", "accepted": ["anderzijds", "aan de andere kant"], "id": "u22q4"}, {"type": "multiple_choice", "prompt": "¿Dónde va «echter» en una frase natural?", "options": ["Ik wilde komen; ik had echter geen tijd.", "Ik wilde komen; echter ik had geen tijd.", "Ik wilde komen; ik echter had geen tijd."], "answer": "Ik wilde komen; ik had echter geen tijd.", "id": "u22q5"}]'::jsonb)
